import type { Drill } from "./types";

// Construction / senior drills, keyed by module slug — 25 per module.
// Persona: a construction project manager / contractor-owner dealing with clients,
// developers, banks, subs, and municipalities. Merged into course.ts.
export const CONSTRUCTION_SENIOR_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-constr-senior-01","level":"senior","profession":"construction","title":"The change order buried in backstory","scenario":"Excavation hit rock that the geotech report missed. You need the developer to approve a $64,000 change order this week or the foundation crew demobilizes. Your draft email opens with three paragraphs about the soil borings.","task":"Write a 2-3 sentence email that puts the approval ask and the deadline in the first sentence.","tips":["Sentence one: the dollar amount, what it's for, and the date you need a signature.","The geotech history is support — put it below or attach it.","Name the consequence of waiting: crew demobilizes, remobilization costs more."],"focus":["clarity","impact"],"placeholder":"I need your signature on CO-014 ($64,000, rock excavation) by Friday —"},
    {"id":"lead-constr-senior-02","level":"senior","profession":"construction","title":"The 60-days-overdue pay app call","scenario":"Pay application #7, worth $212,000, is 60 days overdue and you're about to call the developer's controller. Your instinct is to warm up with small talk about the project before raising the money.","task":"Write your opening two sentences for the call, leading with the amount and what you need.","tips":["State the invoice, the amount, and the days overdue in the first breath.","Ask for a specific commitment: a payment date, not 'an update'.","Friendly tone and a direct opening are not in conflict."],"focus":["clarity","impact"],"placeholder":"I'm calling about pay app 7 — $212,000, now 60 days past due."},
    {"id":"lead-constr-senior-03","level":"senior","profession":"construction","title":"The failed pour, the buried date","scenario":"Yesterday's slab inspection failed on rebar spacing and the pour is off. The client texts asking what's happening. Your drafted reply walks through the inspector's comments before getting to the new pour date.","task":"Write a 2-sentence text that leads with the new pour date and the fix.","tips":["The client's real question is 'when' — answer it first.","One clause on the cause is enough in a text.","Say who is fixing it and that the schedule impact is contained (if true)."],"focus":["concision","clarity"],"placeholder":"New pour date is Thursday — inspection flagged rebar spacing and we're correcting it today."},
    {"id":"lead-constr-senior-04","level":"senior","profession":"construction","title":"The sub who didn't show","scenario":"The drywall sub failed to man the job for the third day and interior finishes are now the critical path. You're updating the developer. Your draft recounts every call you made to the sub before naming the schedule impact.","task":"Write a 2-3 sentence update that leads with the impact and your recovery move.","tips":["Lead with what it means for the project: days at risk, on which milestone.","Your recovery action belongs in sentence two, not paragraph four.","The saga of unanswered calls is background at best."],"focus":["structure","impact"]},
    {"id":"lead-constr-senior-05","level":"senior","profession":"construction","title":"The OAC meeting opener","scenario":"You're chairing the monthly owner-architect-contractor meeting. The real news: substantial completion has slipped two weeks because of the switchgear lead time. You're tempted to open with the safety stats and work through the agenda before saying it.","task":"Write the first two sentences of your meeting opening, leading with the slip.","tips":["Executives forgive bad news delivered first; they resent it delivered last.","Give the new date, the driver, and the mitigation in the opening breath.","Then run the agenda — the room can listen once the headline is out."],"focus":["clarity","impact"],"placeholder":"Before we start the agenda: substantial completion moves two weeks, to March 28, driven by switchgear delivery."},
    {"id":"lead-constr-senior-06","level":"senior","profession":"construction","title":"The go/no-go that hides its ask","scenario":"A tender for a $9M municipal recreation centre closes Friday. You need your business partner's go/no-go decision by Wednesday so estimating can finish. Your draft memo describes the project scope for a page before asking.","task":"Write a 2-3 sentence message that puts the decision and deadline first.","tips":["Open with: 'I need a go/no-go by Wednesday on the rec centre bid.'","Give the two or three facts that drive the decision, nothing else.","A buried ask gets a late answer — and estimating pays for it."],"focus":["clarity","concision"],"placeholder":"I need your go/no-go by Wednesday noon on the $9M rec centre tender."},
    {"id":"lead-constr-senior-07","level":"senior","profession":"construction","title":"The draw request the bank can approve","scenario":"You need the lender's inspector on site by the 15th so the next construction draw funds on time — otherwise you're floating $340,000 in sub payables. Your email draft opens with a general project update.","task":"Write a 2-sentence email that leads with the inspection request and the date.","tips":["The bank contact triages by the first line — make it the ask.","Name the funding consequence briefly: it justifies the urgency.","Project status is an attachment, not the opening."],"focus":["clarity","impact"]},
    {"id":"lead-constr-senior-08","level":"senior","profession":"construction","title":"The permit answer they're waiting for","scenario":"The building permit finally cleared plan review after a six-week delay. The client, the architect, and two subs have all been asking. Your update email starts with a history of the review comments.","task":"Write a 1-2 sentence update that leads with the news and the mobilization date.","tips":["'Permit is issued, we mobilize Monday' is the whole headline.","Everyone downstream plans off your first sentence.","The review saga is optional reading — link or attach it."],"focus":["concision","clarity"],"placeholder":"Permit is issued. We mobilize Monday the 4th —"},
    {"id":"lead-constr-senior-09","level":"senior","profession":"construction","title":"The incident call to the owner","scenario":"A worker fell from a scaffold this morning; he's in hospital, stable, and the site is secured with the regulator notified. You must call the building owner before they hear it elsewhere. You're tempted to start with how the morning unfolded.","task":"Write your opening two sentences, leading with the person's condition and the site status.","tips":["First: the worker is stable and being cared for — the human headline.","Second: site secured, regulator notified, investigation underway.","The sequence of events comes later, and only what's confirmed."],"focus":["clarity","structure"],"placeholder":"I'm calling with news you should hear from me first: a worker fell this morning — he's in hospital and stable."},
    {"id":"lead-constr-senior-10","level":"senior","profession":"construction","title":"The RFI with the question on top","scenario":"You're writing an RFI to the architect: the mechanical drawings show a duct run through a structural beam. Your draft describes the drawing sheets and the site condition for a paragraph before asking anything.","task":"Rewrite the RFI opening so the question comes first, in one sentence.","tips":["Lead with the conflict and the question: 'Which governs?'","Sheet references are support — cite them after the question.","Add the date you need the answer to protect the schedule."],"focus":["clarity","precision"],"placeholder":"Please confirm which governs: M-301 routes a 24-inch duct through the beam shown on S-204."},
    {"id":"lead-constr-senior-11","level":"senior","profession":"construction","title":"The sub recommendation, stated","scenario":"The developer asked which of two mechanical subs to award. You've analyzed both bids and clearly favour one, but your draft walks through a two-page comparison before naming a pick.","task":"Rewrite so your recommendation is the first sentence, with the top two reasons after.","tips":["State the pick and the price in sentence one.","Give the two reasons that would survive a challenge.","The full comparison is an attachment for the diligent."],"focus":["structure","clarity"],"placeholder":"Award mechanical to Keller HVAC at $1.41M —"},
    {"id":"lead-constr-senior-12","level":"senior","profession":"construction","title":"The steel price with a fuse on it","scenario":"Your steel supplier's quote expires in five days, and prices are moving up 4% after that — about $38,000 on this job. You need the owner's approval to purchase early. Your draft opens with market commentary.","task":"Write a 2-3 sentence message that leads with the ask and the deadline.","tips":["Open with: approve the buy by Thursday or the price rises $38,000.","One sentence of market context is plenty.","Make the do-nothing cost explicit — that's what moves approvals."],"focus":["impact","precision"],"placeholder":"I need approval by Thursday to lock steel at the current quote — after that it's roughly $38,000 more."},
    {"id":"lead-constr-senior-13","level":"senior","profession":"construction","title":"The punch-list finish line","scenario":"The punch list is down to zero and you want the architect to schedule the final review walkthrough so you can invoice the last draw. Your email draft recaps the whole punch process before asking for a date.","task":"Write a 2-sentence email that leads with the request for a walkthrough date.","tips":["Ask for the date in sentence one; offer two options to make it easy.","'Punch complete' is the proof — one clause covers it.","Every day without the walkthrough delays your final payment."],"focus":["clarity","concision"]},
    {"id":"lead-constr-senior-14","level":"senior","profession":"construction","title":"The voicemail the inspector will act on","scenario":"You need the electrical inspector back for a reinspection before you can close the ceilings — every day of waiting stalls three trades. You get his voicemail. You tend to ramble on recordings.","task":"Write a 3-sentence voicemail script that leads with the request and the timing.","tips":["Name, project, request, and preferred day — in that order, fast.","Say what's staged and ready so he knows it won't be a wasted trip.","Leave your number twice: start and end."],"focus":["concision","clarity"],"placeholder":"This is Dana Reyes, GC at 400 Harbourfront — requesting electrical reinspection, ideally Tuesday."},
    {"id":"lead-constr-senior-15","level":"senior","profession":"construction","title":"The daily report that buried the crane","scenario":"Your superintendent's daily report mentions in line 14 that the tower crane was down for four hours. You're forwarding the highlights to the developer, and the crane outage is the only thing that matters today.","task":"Write a 2-sentence summary that leads with the crane outage and its schedule effect.","tips":["Pull the one material fact to the top; don't forward the buried version.","Say what it cost — hours, activities affected — and whether it recurs.","Everything routine can stay in the attached report."],"focus":["structure","impact"]},
    {"id":"lead-constr-senior-16","level":"senior","profession":"construction","title":"The move-in question, answered","scenario":"The homeowner on your custom build emails: 'Can we still move in by August 1?' The honest answer is August 15, because the cabinet delivery slipped. Your draft explains the cabinet supply chain before giving any date.","task":"Write a 2-3 sentence reply that gives the date in the first sentence.","tips":["Answer the question asked — a date — before anything else.","One sentence on the driver, one on what you're doing to protect the new date.","A straight answer early beats a soft answer late."],"focus":["clarity","audience"],"placeholder":"Realistically, August 15 — cabinets slipped two weeks at the factory."},
    {"id":"lead-constr-senior-17","level":"senior","profession":"construction","title":"The cure notice cover note","scenario":"You're issuing a formal 48-hour cure notice to the roofing sub for non-performance, and you're emailing their owner directly so it doesn't land cold. Your draft eases in with two paragraphs about the relationship.","task":"Write a 2-3 sentence cover note that states what the attached notice is and what happens next.","tips":["Sentence one: a cure notice is attached, and what triggers it.","State the deadline and the consequence plainly — that's the kindness.","Goodwill language can close the note, not open it."],"focus":["clarity","impact"]},
    {"id":"lead-constr-senior-18","level":"senior","profession":"construction","title":"The budget report headline","scenario":"Your monthly cost report shows the project trending $180,000 over the GMP, driven by concrete overruns and the rock change. The report is twelve pages. The developer will read one sentence of your cover email.","task":"Write that one-sentence cover line, plus one sentence on the next step.","tips":["Headline = the trend number and the two drivers.","Don't average the bad news away — name it.","Sentence two: what you propose to do about it, and when you'll discuss."],"focus":["precision","impact"],"placeholder":"Cost forecast is trending $180K over GMP, driven by concrete quantities and the rock CO —"},
    {"id":"lead-constr-senior-19","level":"senior","profession":"construction","title":"The retainage release request","scenario":"Substantial completion was certified 45 days ago and the lien period has expired, so the owner is holding $95,000 of your retainage past the contract terms. Your draft letter opens with a history of the project.","task":"Write a 2-sentence request that leads with the release ask, the amount, and the contract basis.","tips":["Cite the amount, the contract clause, and the trigger date in sentence one.","Ask for payment by a specific date.","Save the project retrospective for the closeout letter."],"focus":["precision","clarity"],"placeholder":"We request release of the $95,000 retainage now due under GC 9.8 —"},
    {"id":"lead-constr-senior-20","level":"senior","profession":"construction","title":"The warranty call, answered first","scenario":"A client who took occupancy three months ago emails photos of a leak stain on the ceiling below a bathroom. They're anxious. Your draft opens by explaining warranty procedure and exclusions.","task":"Write a 2-3 sentence reply that leads with what you'll do and when.","tips":["Sentence one: we're on it — plumber on site by a named day.","Reassure with action, not with procedure.","Warranty terms matter later; a fast response is the headline."],"focus":["audience","clarity"],"placeholder":"We'll have our plumber there Thursday morning to open the ceiling and find the source."},
    {"id":"lead-constr-senior-21","level":"senior","profession":"construction","title":"The bonding capacity ask","scenario":"To bid a $14M school project you need your surety to raise your single-job bonding limit from $10M. Your draft letter to the bonding agent walks through your company history before making the request.","task":"Write a 2-sentence opening that states the request and the deadline tied to the tender date.","tips":["Lead with the number you need and when the tender closes.","Follow with the one or two financials that carry the case.","Your agent forwards your first lines to the underwriter — write for that."],"focus":["clarity","precision"]},
    {"id":"lead-constr-senior-22","level":"senior","profession":"construction","title":"The road-occupancy meeting request","scenario":"You need a lane closure on a downtown street for eight weeks of crane operations, and the city's transportation department is slow to engage. You're emailing the manager to get a meeting. Your draft describes the whole project first.","task":"Write a 2-sentence email that leads with the meeting request and what you need decided.","tips":["Ask for the meeting and name the decision: an eight-week lane closure permit.","Give the dates and the one constraint that makes timing tight.","City staff answer specific asks faster than project descriptions."],"focus":["clarity","concision"],"placeholder":"I'd like 30 minutes with you next week to work through a lane-closure permit for 8 weeks of crane picks at 220 King."},
    {"id":"lead-constr-senior-23","level":"senior","profession":"construction","title":"The winter decision, framed as one","scenario":"Cold weather is coming and the building isn't closed in. The owner must choose: spend $70,000 on temporary heat and hoarding, or pause interior work for eight weeks. Your draft email explains construction sequencing at length before presenting the choice.","task":"Write a 2-3 sentence email that puts the decision and its two options first.","tips":["Frame it in sentence one: two options, one decision, needed by a date.","Attach a cost/schedule line for each option — one line each.","State your recommendation; you're paid for judgment, not menus."],"focus":["structure","clarity"],"placeholder":"You have a decision to make by Nov 1: spend $70K on temporary heat, or pause interiors eight weeks."},
    {"id":"lead-constr-senior-24","level":"senior","profession":"construction","title":"The delay notice that must land today","scenario":"The contract requires written notice of delay within 10 days of the event, and day 9 is today: the city's watermain work blocked your site access for a week. Your draft buries the notice language under courtesies.","task":"Write the first two sentences of the notice, stating that it is formal notice, the event, and the dates.","tips":["Say 'this is written notice of delay under GC 6.5' in sentence one.","Name the event and the affected dates precisely.","Politeness can follow; preserving the claim comes first."],"focus":["precision","clarity"],"placeholder":"This letter is formal notice of delay under GC 6.5: city watermain work blocked site access March 3-10."},
    {"id":"lead-constr-senior-25","level":"senior","profession":"construction","title":"The referral ask after a good job","scenario":"You just closed out a smooth office fit-out and the client is happy. You want two things: a reference letter and an introduction to their sister company, which is planning a warehouse. Your draft is a page of thanks with the asks vanishing at the end.","task":"Write a 3-sentence note that pairs the thanks with both asks up front.","tips":["Gratitude and the ask can share the first sentence.","Name both asks specifically: a reference letter, an intro to a named person.","Make each easy: offer a draft letter, suggest a short call."],"focus":["clarity","audience"]}
  ],
  "start-with-the-audience": [
    {"id":"audience-constr-senior-01","level":"senior","profession":"construction","title":"Float, for a homeowner","scenario":"Your custom-home client saw the schedule and is alarmed that framing 'finished five days late.' In fact the delay ate float and the completion date is unchanged. You start drafting an explanation full of critical path and float terminology.","task":"Write a 2-3 sentence reply that explains it in the client's terms: what it means for their move-in.","tips":["Their stake is the move-in date — anchor on that.","Translate 'float' into 'built-in slack we planned for.'","One reassuring fact beats three scheduling terms."],"focus":["audience","clarity"],"placeholder":"Your move-in date hasn't moved. The framing delay used up slack we build into the schedule for exactly this —"},
    {"id":"audience-constr-senior-02","level":"senior","profession":"construction","title":"Unforeseen conditions, in money terms","scenario":"You're explaining a $48,000 change order to a developer whose only question is why they should pay it. Your draft leads with soil classifications and the geotech report's boring logs.","task":"Write a 3-sentence justification framed around the developer's stake: contract risk allocation and cost.","tips":["Lead with the contractual point: subsurface risk sits with the owner under this contract.","Then the money: what it costs, what it would cost to dispute.","Boring logs are exhibits, not the argument."],"focus":["audience","impact"]},
    {"id":"audience-constr-senior-03","level":"senior","profession":"construction","title":"The failed inspection, minus the code cites","scenario":"The framing inspection failed on stair stringer spacing and a missing beam hanger. The owner — a retired teacher building her forever home — is worried the house is unsafe. Your draft quotes code sections.","task":"Write a 2-3 sentence explanation that addresses her real worry and names the fix.","tips":["Her question is 'is my house sound?' — answer that first.","Describe the fix in physical terms: add hangers, respace stringers, reinspect Friday.","Code sections prove nothing to someone who can't read them."],"focus":["audience","clarity"],"placeholder":"Nothing about the house is unsafe — the inspector flagged two items we fix this week."},
    {"id":"audience-constr-senior-04","level":"senior","profession":"construction","title":"Progress, in the lender's language","scenario":"The bank's loan officer needs your monthly update. You drafted a builder's update: trades on site, areas of work, weather. The lender cares about percent complete against the draw schedule, budget variance, and anything threatening loan covenants.","task":"Rewrite the update as 3-4 sentences in the lender's terms.","tips":["Lead with percent complete versus draw schedule.","Flag budget variance and contingency remaining — that's their risk lens.","Trades and weather only matter if they move a draw."],"focus":["audience","precision"],"placeholder":"The project is 62% complete against a 60% draw schedule; contingency stands at $210K of the original $300K."},
    {"id":"audience-constr-senior-05","level":"senior","profession":"construction","title":"Value engineering for a first-timer","scenario":"Your first-time commercial client is $200,000 over budget at design. You have VE options: reduce the curtain wall, switch to a different roof assembly, simplify the lobby. Your draft is a spreadsheet of assemblies and unit rates.","task":"Write a 3-4 sentence introduction that frames the options by what the client keeps and gives up.","tips":["Frame each option as a trade: what they save, what changes for their tenants.","Their altitude is 'look, function, cost' — not assemblies and R-values.","End with which one you'd take and why."],"focus":["audience","structure"]},
    {"id":"audience-constr-senior-06","level":"senior","profession":"construction","title":"Brief the proposal writer","scenario":"Your marketing coordinator is drafting the RFP response for a hospital renovation and asked why your firm wins work like this. Your instinct is a list of past projects. She needs the differentiators in plain language she can build a narrative from.","task":"Write 3 sentences naming your firm's edge in words a non-builder can reuse.","tips":["Say why clients pick you, not what you've built.","Translate 'phased occupied renovation experience' into what it means for a hospital that can't close.","Give her the sentence you'd want the selection committee to repeat."],"focus":["audience","impact"]},
    {"id":"audience-constr-senior-07","level":"senior","profession":"construction","title":"One audience for the delay story","scenario":"You're documenting a 6-week delay caused by late owner decisions. Your lawyer needs contract notice language; the client needs a relationship-preserving explanation. You're writing one email and trying to serve both.","task":"Decide the primary audience and write the 2-3 sentence opening for that reader.","tips":["Pick one reader; the other gets a separate document.","To the client: facts, dates, and the path forward — no legal posturing.","To the lawyer: events, notice dates, and clause references — no softening."],"focus":["audience","structure"]},
    {"id":"audience-constr-senior-08","level":"senior","profession":"construction","title":"The spec conflict, for the owner","scenario":"The spec calls for one roofing membrane; the drawings detail another. The architect is slow to resolve it. You're escalating to the owner, but your draft is written in spec-section numbers the owner won't follow.","task":"Write a 2-3 sentence escalation framed in the owner's stakes: cost, schedule, and the decision needed.","tips":["The owner's question: what does this cost me and who decides?","Name the deadline: order the membrane by X or the roof slips.","Spec sections go in parentheses, not headlines."],"focus":["audience","clarity"],"placeholder":"We need a roofing decision from your architect by the 12th, or the roof — and everything under it — slips."},
    {"id":"audience-constr-senior-09","level":"senior","profession":"construction","title":"Retainage, explained to a new sub","scenario":"A young electrical sub on his first commercial job is angry that 10% is being held from every payment. He thinks you're shorting him. Your draft quotes the subcontract clause back at him.","task":"Write a 3-sentence explanation of retainage in terms of how and when he gets paid.","tips":["Answer his real question: it's his money, held not taken, released at defined triggers.","Give the dates: substantial completion, lien period expiry.","Quoting the clause proves you're right; explaining it keeps the sub."],"focus":["audience","clarity"],"placeholder":"The 10% is holdback, not a deduction — it's released to you when..."},
    {"id":"audience-constr-senior-10","level":"senior","profession":"construction","title":"The letter to the neighbours","scenario":"Next month you start pile driving on an infill site, which means six weeks of noise starting at 7 a.m. and periodic sidewalk closures. You're writing the notification letter to residents. Your draft reads like a construction schedule.","task":"Write a 3-4 sentence letter opening that speaks to what residents will experience and whom to call.","tips":["Their stake: noise, hours, parking, safety of the sidewalk route.","Give real hours and real dates, then the one phone number that answers.","A respectful, specific letter prevents a month of complaint calls to the city."],"focus":["audience","clarity"]},
    {"id":"audience-constr-senior-11","level":"senior","profession":"construction","title":"Two minutes before council","scenario":"You have two minutes at a council meeting to support your client's development application, which residents oppose. Your instinct is to talk construction logistics. Council's stakes are traffic, tax base, and complaints they'll receive.","task":"Write your first three spoken sentences, aimed at what council weighs.","tips":["Open with the community benefit in council's terms: jobs, housing units, tax revenue.","Address the top objection — construction traffic — with a specific commitment.","You're not the audience; the councillors' constituents are."],"focus":["audience","impact"]},
    {"id":"audience-constr-senior-12","level":"senior","profession":"construction","title":"The orientation that gets remembered","scenario":"You're giving the safety orientation to four new labourers, two of whom have never been on a high-rise site. Your standard script is twenty minutes of policy citations. The one thing that kills people on your site is falls and swinging loads.","task":"Write the 3 sentences you'd deliver first, in plain words a first-day worker keeps.","tips":["Lead with the two things most likely to kill them here, and the rule for each.","Policy numbers evaporate; 'never walk under the crane's load, ever' sticks.","Tell them who to ask when unsure — and that asking is expected."],"focus":["audience","impact"],"placeholder":"Two things on this site can kill you: falls and crane loads. Here's the rule for each."},
    {"id":"audience-constr-senior-13","level":"senior","profession":"construction","title":"The adjuster's checklist","scenario":"A windstorm tore off roof sheathing and soaked two floors of drywall. You're writing to the insurance adjuster. Your draft narrates the storm dramatically. The adjuster needs dates, cause, scope of damage, mitigation steps taken, and a documented cost estimate.","task":"Write a 3-4 sentence first paragraph organized around what the adjuster needs to approve the claim.","tips":["Date of loss, cause, affected areas, and mitigation — in the first two sentences.","Attach photos and the estimate; reference them, don't describe them.","Write for the file reviewer who never visits the site."],"focus":["audience","precision"]},
    {"id":"audience-constr-senior-14","level":"senior","profession":"construction","title":"The scope add and the critical path","scenario":"Mid-project, the client wants to add a mezzanine. They think it's a simple add because 'the crew is already there.' The steel is a 10-week procurement and the design change stalls the permit. Your draft lectures about critical path method.","task":"Write a 2-3 sentence response that translates the impact into their decision: cost, weeks, and a decision date.","tips":["Their language: 'this adds X weeks and $Y, and here's why.'","One concrete driver — 10-week steel lead time — explains more than CPM theory.","Give them a decision date that keeps the option open."],"focus":["audience","clarity"],"placeholder":"The mezzanine is doable, but it adds about six weeks and $190K — the steel alone is a 10-week order."},
    {"id":"audience-constr-senior-15","level":"senior","profession":"construction","title":"Lien rights, said carefully","scenario":"A commercial client is 75 days behind on payment and you must mention lien rights without torching the relationship. Your draft either buries the point in apology or reads like a threat letter.","task":"Write a 3-sentence message that states the deadline-driven step plainly while keeping the door open.","tips":["Frame it as a statutory deadline you don't control: 'to preserve rights, we must file by X.'","Pair it with the off-ramp: payment or a signed schedule by a named date.","Neither grovel nor threaten — describe what happens and when."],"focus":["audience","impact"],"placeholder":"I want to flag a deadline before it becomes adversarial: to preserve lien rights we'd have to file by the 21st."},
    {"id":"audience-constr-senior-16","level":"senior","profession":"construction","title":"The hairline crack walkthrough","scenario":"At the pre-occupancy walkthrough, the buyers spot a hairline crack in the basement slab and go quiet. It's normal shrinkage cracking. Your draft explanation involves water-cement ratios and curing.","task":"Write the 2-3 sentences you'd say, addressing what they're actually afraid of.","tips":["Their fear is structural failure and resale value — speak to that.","'Concrete shrinks as it dries; this crack is cosmetic, and here's how you'd know if it weren't.'","Tell them what's covered and what you'll monitor — specifics calm people."],"focus":["audience","clarity"]},
    {"id":"audience-constr-senior-17","level":"senior","profession":"construction","title":"Board altitude, not builder altitude","scenario":"You're presenting the condo project's status to the developer's board — finance people who meet quarterly. Your slides are site photos and trade-by-trade progress. The board decides one thing today: approve the revised financing plan.","task":"Write the 2-3 sentence project summary you'd open with, calibrated to a quarterly board.","tips":["Board altitude: schedule vs plan, cost vs budget, the decision needed today.","One trade-level detail maximum, and only if it drives the decision.","Photos entertain; variance numbers decide."],"focus":["audience","structure"],"placeholder":"Since you last met: construction is 71% complete, 3 weeks behind plan, and $400K of the $600K contingency remains. Today we need..."},
    {"id":"audience-constr-senior-18","level":"senior","profession":"construction","title":"The energy code upgrade, sold on payback","scenario":"The new energy code forces a costlier wall assembly, and your client sees only the $85,000 add. There's a real story in operating savings and tenant demand, but your draft explains R-values and air barriers.","task":"Write a 2-3 sentence explanation framed in the owner's return: operating cost, leasing, resale.","tips":["Translate the assembly into dollars per year of heating/cooling saved.","Name the market angle: tenants and buyers now ask for the certificate.","R-values are the engineer's units, not the owner's."],"focus":["audience","impact"]},
    {"id":"audience-constr-senior-19","level":"senior","profession":"construction","title":"The pitch to a project engineer","scenario":"You're trying to hire a sharp project engineer away from a big national GC. Your draft pitch lists your firm's revenue and project types. What she cares about: scope of responsibility, path to PM, and not being a cog.","task":"Write 3 sentences pitching the role in terms of her stakes, not your firm's stats.","tips":["Lead with what she'd own in year one that she can't own where she is.","Name the path: 'running your own $5M job within 18 months' beats 'growth opportunities.'","Firm stats are backup for the offer letter, not the hook."],"focus":["audience","impact"]},
    {"id":"audience-constr-senior-20","level":"senior","profession":"construction","title":"Winter concrete, for the worried client","scenario":"Your client read online that 'concrete poured in winter fails' and wants to halt the foundation pour scheduled for next week at -5°C. Your crew has heated, hoarded, and poured in colder. Your draft is a lecture on hydration chemistry.","task":"Write a 2-3 sentence reassurance that speaks to their real question: will my foundation be sound?","tips":["Answer the fear first: yes, and here is exactly what we do differently in winter.","Name the specific protections — heated enclosure, warm water, test cylinders — as proof of method.","Offer the verification: cylinder break results they can see."],"focus":["audience","clarity"],"placeholder":"Your foundation will be as strong as a summer pour — winter concrete fails only when it's poured unprotected, and ours isn't."},
    {"id":"audience-constr-senior-21","level":"senior","profession":"construction","title":"The geotech finding, translated","scenario":"The geotech report for your developer's next site found 4 metres of compressible fill, meaning piles instead of spread footings. The developer skims reports and thinks in pro formas. Your draft quotes the report's soil descriptions.","task":"Write a 2-3 sentence summary that translates the finding into the pro forma: cost, time, and what to do before closing on the land.","tips":["Lead with the number: piles add roughly $X and Y weeks versus footings.","Tie it to their live decision — the land isn't closed yet.","The soil description is why; the pro forma hit is what."],"focus":["audience","precision"],"placeholder":"The soils change your foundation math: piles instead of footings, roughly $350K and four extra weeks."},
    {"id":"audience-constr-senior-22","level":"senior","profession":"construction","title":"Foreman or owner — pick the reader","scenario":"The masonry sub's work is sloppy: struck joints inconsistent, two lifts out of plumb. You could message their site foreman, whom you like, or their owner, whom the contract points to. You drafted one message trying to reach both.","task":"Choose the right recipient and write the 2-3 sentence message for that specific reader.","tips":["Performance-of-contract issues go to the party who signed the contract.","To the owner: defect, standard, remedy, date. To the foreman: today's fix.","One reader, one register — a hybrid message moves neither."],"focus":["audience","structure"]},
    {"id":"audience-constr-senior-23","level":"senior","profession":"construction","title":"Allowances at contract signing","scenario":"You're walking custom-home clients through their contract. The $40,000 in allowances (lighting, tile, appliances) is where every relationship on this job type goes wrong. Your standard explanation is contract language they nod through without absorbing.","task":"Write a 3-sentence plain-language explanation of allowances that prevents the future fight.","tips":["Say what happens in both directions: pick above the allowance, pay the difference; below, get the credit.","Give a lived example: 'the faucet you liked at the showroom is $900; the allowance assumes $300.'","This is the paragraph that saves the relationship in month seven."],"focus":["audience","clarity"]},
    {"id":"audience-constr-senior-24","level":"senior","profession":"construction","title":"One sentence for the reporter","scenario":"A crane lift over the street stopped traffic for an hour this morning and a local reporter calls for comment. Your instincts are to explain rigging engineering. Her audience is commuters; her deadline is 4 p.m.; she will use one sentence.","task":"Write the one quotable sentence, plus one background sentence, for the reporter.","tips":["Speak to her readers: why it happened, that it was planned/safe, when it recurs.","Give her the quote you want printed — she'll take the clearest sentence you say.","No jargon survives an editor; don't offer any."],"focus":["audience","concision"],"placeholder":"We stopped traffic for an hour to lift the building's rooftop units safely over the street — it was planned with the city, and the next lift is Saturday morning to avoid the rush."},
    {"id":"audience-constr-senior-25","level":"senior","profession":"construction","title":"Punch list, for the tenant","scenario":"An office tenant is moving in next week and their operations manager asks what 'punch list ongoing' means for their move. Your draft explains the architect's certification process. She needs to know: can we move in, what will be unfinished, will workers be in our space?","task":"Write a 3-sentence answer organized entirely around her three questions.","tips":["Answer her questions in her order: move-in yes/no, what's unfinished, who'll be around.","Give real specifics: 'touch-up painters, two mornings, before 8 a.m.'","Certification process is your problem; her problem is moving 40 staff."],"focus":["audience","clarity"]}
  ],
  "structure-that-carries": [
    {"id":"structure-constr-senior-01","level":"senior","profession":"construction","title":"The monthly report's governing idea","scenario":"Your monthly report to the developer covers schedule, cost, safety, procurement, and quality — five sections that read like five separate memos. This month the single story is: the project is recoverable, if three decisions land by the 15th.","task":"Write the governing-idea sentence and name the 3 buckets your report will hang from it.","tips":["One sentence at the top that the whole report supports.","Buckets should be the three decisions, not the five departments.","Everything that doesn't support the governing idea moves to an appendix."],"focus":["structure","clarity"],"placeholder":"The schedule is recoverable if three decisions land by the 15th: (1)..."},
    {"id":"structure-constr-senior-02","level":"senior","profession":"construction","title":"SCQA for the delay claim","scenario":"You're writing the narrative for a 6-week delay claim against the owner for late drawing releases. Your draft is a chronological diary of 40 events. The reviewer — likely a mediator someday — needs the logic, not the diary.","task":"Write the Situation, Complication, Question, and Answer as one sentence each.","tips":["Situation: the contractual baseline both sides agreed to.","Complication: the owner-caused events that broke it, in one sentence.","Answer: the entitlement — weeks and dollars — that the 40 events will then evidence."],"focus":["structure","precision"],"placeholder":"S: The contract required owner drawing releases per the approved schedule. C: Eleven releases arrived 3-9 weeks late..."},
    {"id":"structure-constr-senior-03","level":"senior","profession":"construction","title":"PREP: why are you over budget?","scenario":"At the owner's meeting, the CFO asks point-blank: 'Why is this project over budget?' You know the three drivers cold, but under the sudden spotlight you tend to narrate the whole job history.","task":"Write a spoken PREP answer (Point, Reason, Example, Point) in 4-5 sentences.","tips":["Point first: 'We're $180K over, and 80% of it is two events.'","Reason and example: the rock CO and concrete quantities, with numbers.","Land the point again with what happens next — the forecast, not the past."],"focus":["structure","clarity"],"placeholder":"We're $180K over the GMP, and two events explain almost all of it."},
    {"id":"structure-constr-senior-04","level":"senior","profession":"construction","title":"Twelve open items, three buckets","scenario":"Your OAC agenda has twelve open items: two unpaid COs, three unanswered RFIs, a permit renewal, two owner-supplied equipment delays, a colour selection, retainage terms, a warranty question, and site parking. Read as a list, the meeting will sprawl for two hours.","task":"Group the twelve into 3 named buckets and write the one-line framing you'd open the meeting with.","tips":["Group by the action needed — decisions, money, information — not by trade or date.","Name each bucket by who must act: 'three things needing owner decisions this week.'","The framing sentence tells the room how long each bucket gets."],"focus":["structure","concision"]},
    {"id":"structure-constr-senior-05","level":"senior","profession":"construction","title":"The bid's executive summary","scenario":"Your proposal for a $12M seniors' residence has 60 pages of approach, schedule, and team resumes. The selection committee will read the one-page executive summary and skim the rest. Your draft summary describes your company.","task":"Write a governing-idea opening sentence and the 3 support points the summary will carry.","tips":["The governing idea answers their question: why is this bid the safe, smart choice?","Three supports max — schedule certainty, comparable projects, the named team.","Every sentence in the summary should make the committee's shortlist memo easier to write."],"focus":["structure","impact"],"placeholder":"We will deliver this residence for $11.9M and 14 months, with the same team that delivered two occupied-site seniors' projects on schedule —"},
    {"id":"structure-constr-senior-06","level":"senior","profession":"construction","title":"The recovery schedule, structured","scenario":"You're presenting a recovery plan after a 4-week slip. You have fifteen actions: resequencing, added crews, weekend work, early procurement, scope pull-forwards. Presented as fifteen items, the owner hears chaos, not a plan.","task":"Organize the recovery plan into 3 named workstreams and write the opening sentence that frames them.","tips":["Buckets like 'resequence, add capacity, buy time on procurement' carry fifteen actions cleanly.","Open with the outcome: the date you recover to, then how.","Each bucket needs an owner and a proof point (dates, crew counts)."],"focus":["structure","clarity"],"placeholder":"We recover the four weeks by January through three moves: resequencing interiors, adding a second drywall crew, and pre-purchasing the switchgear."},
    {"id":"structure-constr-senior-07","level":"senior","profession":"construction","title":"Prequal findings, grouped","scenario":"You reviewed five mechanical subs for prequalification. Your notes are a jumble: bond capacity, safety records, current backlog, reference calls, financials, one pending lawsuit. The developer asked for a recommendation memo.","task":"Write the memo's first sentence (the recommendation) and the 3 headings the evidence will sit under.","tips":["Recommendation first; the structure exists to defend it.","Headings by decision criteria — capacity, track record, financial strength — not by sub.","The lawsuit goes under the heading it threatens, stated plainly."],"focus":["structure","clarity"]},
    {"id":"structure-constr-senior-08","level":"senior","profession":"construction","title":"The kickoff agenda that sets the job","scenario":"You're writing the agenda for a project kickoff with the owner, architect, and key subs — the meeting that sets communication rules for two years. Your draft is a topic list: 'schedule, safety, RFIs, billing, misc.'","task":"Rewrite the agenda as 3-4 outcome-based items, each phrased as the decision or agreement the meeting must produce.","tips":["'Agree the RFI turnaround: 5 working days' beats 'RFIs' as an agenda line.","Sequence by dependency: communication rules before schedule commitments.","If an item produces no agreement, it's an email, not agenda time."],"focus":["structure","precision"]},
    {"id":"structure-constr-senior-09","level":"senior","profession":"construction","title":"SCQA for the bank","scenario":"Interest carrying costs are hurting your developer client because the draw schedule assumed faster early progress. You're helping them ask the bank to restructure draws. Your draft opens with an apology for the slow start.","task":"Write the SCQA — one sentence each — for the restructure request.","tips":["Situation: the loan and original draw profile. Complication: actual cash curve differs, for documented reasons.","The Question is the bank's: will we be repaid on time? Answer it before asking for anything.","An apology frames weakness; SCQA frames a decision."],"focus":["structure","audience"]},
    {"id":"structure-constr-senior-10","level":"senior","profession":"construction","title":"Self-perform concrete: the pyramid","scenario":"Your partners are debating whether the firm should self-perform concrete instead of subbing it out. You've studied it for a month: margins, equipment, labour risk, bonding, competitors. Your memo draft wanders through all of it.","task":"Write the one-sentence recommendation and the 3 supporting arguments beneath it, one line each.","tips":["Take a position in sentence one — the analysis exists to support it.","Three arguments, each answering a partner's likely objection.","Anything not load-bearing for the recommendation gets cut or appended."],"focus":["structure","clarity"],"placeholder":"We should self-perform concrete starting next fiscal year, for three reasons:"},
    {"id":"structure-constr-senior-11","level":"senior","profession":"construction","title":"The stand-down talk with a spine","scenario":"After a near-miss — a dropped tool from the eighth floor that missed a labourer by a metre — you're addressing the whole site. You have one shot at forty people's attention before they go back to work. Rambling kills it.","task":"Structure a 5-sentence stand-down talk: what happened, why it matters, the one change, effective when.","tips":["One incident, one lesson, one rule change — resist covering everything.","Say the new rule in words a foreman can repeat at lunch.","End with the effective date and who enforces it — structure is what makes it real."],"focus":["structure","impact"],"placeholder":"This morning a wrench fell eight floors and missed Marco by a metre. Here's the one thing that changes today."},
    {"id":"structure-constr-senior-12","level":"senior","profession":"construction","title":"Punch list by responsible party","scenario":"The architect issued a 94-item punch list as one undifferentiated list. Forwarded as-is to your subs, nothing will happen. Sorted and framed, it closes in three weeks.","task":"Write the 2-3 sentence cover note that explains how you've grouped the list and what each party must do by when.","tips":["Group by responsible sub, then by area — that's how work actually gets assigned.","The cover note states the completion date and the walkthrough that verifies it.","A list without owners and dates is a suggestion."],"focus":["structure","clarity"]},
    {"id":"structure-constr-senior-13","level":"senior","profession":"construction","title":"PREP: can you still make the date?","scenario":"The developer's asset manager corners you after a site tour: 'Straight answer — do we still make October 1?' You believe yes, with two conditions. Unstructured, your answer will sound like a hedge.","task":"Write the spoken PREP answer in 4 sentences, with the conditions inside the structure.","tips":["Point: 'Yes, on two conditions.' That's an answer, not a hedge.","Reasons and example: what protects the date and what you've already banked.","Restate the point with the conditions' deadlines attached."],"focus":["structure","clarity"],"placeholder":"Yes — October 1 holds, on two conditions I can name."},
    {"id":"structure-constr-senior-14","level":"senior","profession":"construction","title":"Lessons learned, not war stories","scenario":"The hospital renovation finished 8% over and everyone has a story about why. You're writing the lessons-learned memo for the next PM. Your draft retells the project chronologically, which preserves the pain but not the lessons.","task":"Write the memo's governing sentence and 3 lesson headings, each phrased as an instruction for the next job.","tips":["Lessons are imperatives: 'price occupied-site logistics as its own line item,' not 'logistics were hard.'","Three lessons that would have saved real money beat ten observations.","The chronology is an appendix for the curious."],"focus":["structure","impact"]},
    {"id":"structure-constr-senior-15","level":"senior","profession":"construction","title":"The CO log walks into a dispute","scenario":"You're preparing for a dispute meeting over $310,000 in contested change orders — 14 COs with different causes. Presented CO-by-CO, the meeting becomes 14 small fights. Grouped by cause, it becomes 3 arguments you can win.","task":"Name the 3 cause-based groups and write the one-line framing you'd open the meeting with.","tips":["Group by legal theory: design errors, owner-directed changes, unforeseen conditions.","Win the strongest group first — it sets the standard for the rest.","The framing line tells the other side the meeting is about 3 questions, not 14."],"focus":["structure","impact"],"placeholder":"These fourteen COs are really three questions: who owns design gaps, owner-directed scope, and the soils."},
    {"id":"structure-constr-senior-16","level":"senior","profession":"construction","title":"The pitch for negotiated work","scenario":"You want a repeat client to negotiate their next project with you instead of tendering it. You have the arguments — early input, faster start, open-book cost — but your draft letter sprays them without a spine.","task":"Write the governing claim in one sentence, then the 3 supports in one line each.","tips":["The claim answers their fear: 'negotiated' must not mean 'expensive.'","Supports: what they save (time, redesign), what they see (open book), what they keep (market pricing via sub tenders).","Each support should pre-empt the procurement director's objection."],"focus":["structure","audience"]},
    {"id":"structure-constr-senior-17","level":"senior","profession":"construction","title":"Why the estimate came in high","scenario":"Your estimate for the client's warehouse came in 18% above their budget and they're upset. There are three real reasons: the design grew, the market moved, and their budget was set two years ago. Your draft email apologizes and lists twenty line items.","task":"Structure a 4-sentence explanation: one governing sentence, then the 3 causes with a number each.","tips":["The governing sentence allocates the 18% across the three causes.","Numbers per cause turn a defensive email into an analysis.","End with the path: three VE options that close the gap by $X."],"focus":["structure","precision"],"placeholder":"The 18% gap has three parts: about 8% is design growth since the budget was set, 6% is market escalation, and 4% is..."},
    {"id":"structure-constr-senior-18","level":"senior","profession":"construction","title":"Answering the LD threat","scenario":"The owner's lawyer sent a letter threatening liquidated damages of $5,000/day for late completion. Your response must argue excusable delay. Your draft is an angry chronology. A structured letter — position, grounds, evidence, ask — wins; a rant loses.","task":"Write the response letter's first sentence (your position) and name the 3 grounds it will stand on.","tips":["Position first: the delay is excusable and compensable under named clauses.","Grounds as headings: owner-caused drawing delays, differing site conditions, granted-but-unpriced changes.","The chronology becomes exhibits under each ground — structure turns anger into a case."],"focus":["structure","clarity"]},
    {"id":"structure-constr-senior-19","level":"senior","profession":"construction","title":"Site logistics in three moves","scenario":"The architect asked you to explain site logistics for the tight downtown site to the owner: crane placement, delivery windows, pedestrian protection, laydown, hoisting. Your draft is a tour of the site plan drawing.","task":"Structure the explanation as 3 named principles, each with one supporting specific, in 4-5 sentences total.","tips":["Principles like 'everything arrives just-in-time,' 'the public never walks under work,' 'one crane serves all trades.'","Each principle earns one concrete detail: delivery windows, the covered walkway, crane hours.","A drawing tour informs; principles persuade the owner you've got it handled."],"focus":["structure","clarity"]},
    {"id":"structure-constr-senior-20","level":"senior","profession":"construction","title":"SCQA for early procurement","scenario":"You want the owner to release $600,000 for switchgear and elevators before the GMP is final — unusual, and their board will resist. Written as a plea, it fails. Written as SCQA, the logic does the work.","task":"Write the SCQA in four sentences for the early-release request.","tips":["Situation: lead times on the two items. Complication: they now exceed the schedule's room.","Question (the board's): what happens if we wait? Answer: the release, its protection terms, and the deadline.","Include the safeguard — the money buys assigned purchase orders, not trust."],"focus":["structure","impact"],"placeholder":"S: Switchgear and elevators are 38- and 30-week deliveries. C: Our schedule now has 26 weeks of room..."},
    {"id":"structure-constr-senior-21","level":"senior","profession":"construction","title":"The shortlist interview's skeleton","scenario":"Your firm made the shortlist for a $20M library and you have 20 minutes before the selection panel. Your team wants to cover everything: history, approach, schedule, team, safety, community. Twenty minutes covers three things well or six things badly.","task":"Pick the 3 messages the presentation will carry and write the opening sentence that frames them.","tips":["Choose the three that answer the panel's real question: will this go well for us?","Frame them in the first sentence so the panel can follow the whole 20 minutes.","Everything else survives only as an answer to Q&A."],"focus":["structure","audience"],"placeholder":"In the next twenty minutes we'll show you three things: the team you'd actually get, the schedule we'd sign, and how we keep a public site safe."},
    {"id":"structure-constr-senior-22","level":"senior","profession":"construction","title":"The superintendent's list, sorted","scenario":"Your superintendent calls with a stream of issues: a plugged storm line, the electrician's manpower, a missing door schedule, graffiti, a delivery blocking the neighbour's driveway, and an inspector's comment. You need to relay what matters to the owner's rep today.","task":"Sort the list: write one sentence naming what needs owner action today, and one sentence for what you're handling.","tips":["Two buckets beat six items: 'needs you' and 'handled.'","Only the missing door schedule and the inspector comment likely need the owner's side.","Reporting everything at equal volume trains readers to skim you."],"focus":["structure","concision"]},
    {"id":"structure-constr-senior-23","level":"senior","profession":"construction","title":"The closeout letter that gets you paid","scenario":"You're submitting the closeout package: warranties, as-builts, O&M manuals, lien waivers, final accounting. The cover letter should make releasing the final $140,000 the obvious next step. Your draft just lists the enclosures.","task":"Write a 3-sentence cover letter structured as: everything is complete, here is the proof, here is the payment now due.","tips":["The governing idea: all conditions for final payment are now met.","Map each enclosure to the contract condition it satisfies — that's the proof structure.","End with the amount and the contractual payment deadline."],"focus":["structure","clarity"],"placeholder":"All conditions for final payment under GC 9.10 are now satisfied. Enclosed:"},
    {"id":"structure-constr-senior-24","level":"senior","profession":"construction","title":"PREP: why this sub?","scenario":"The owner questions your award of structural steel to a sub who wasn't the low bidder — $60,000 higher than the cheapest price. You have solid reasons. Delivered as a defensive scramble, they'll sound like excuses.","task":"Write the spoken PREP answer in 4 sentences justifying the award.","tips":["Point: 'We recommended them because the low bid carried $200K of schedule risk.'","Reason with evidence: the low bidder's current backlog and their record on your last job.","Return to the point: cheapest price and lowest cost are different numbers."],"focus":["structure","precision"],"placeholder":"We awarded to Fraser Steel because the low bid was the riskier number —"},
    {"id":"structure-constr-senior-25","level":"senior","profession":"construction","title":"The portfolio review's pyramid","scenario":"You're presenting the year's project portfolio to your partners: nine jobs, mixed results — two strong, five fine, two painful. Your draft goes job by job, which buries the pattern that matters: the painful two were both hard-bid public work.","task":"Write the governing insight in one sentence and the 3 sections of the review beneath it.","tips":["Lead with the pattern, not the roster: where the firm makes and loses money.","Sections by theme — margin by procurement type, overhead recovery, where to bid next year.","Job-by-job detail is the appendix partners can mine later."],"focus":["structure","impact"]}
  ],
  "cut-to-the-bone": [
    {"id":"concise-constr-senior-01","level":"senior","profession":"construction","title":"The CO justification, halved","scenario":"Your change order justification reads: 'It should be noted that due to the fact that unforeseen subsurface conditions were encountered during the course of excavation activities, additional costs were necessarily incurred.' Twenty-eight words saying twelve words' worth.","task":"Rewrite the sentence in 12 words or fewer without losing the claim.","tips":["'It should be noted that' and 'due to the fact that' are pure filler.","'During the course of excavation activities' is 'during excavation.'","Shorter reads as more confident — which is what a contested CO needs."],"focus":["concision","clarity"],"placeholder":"Excavation hit unforeseen rock, adding $64,000 of cost."},
    {"id":"concise-constr-senior-02","level":"senior","profession":"construction","title":"The payment chase, tightened","scenario":"Your third email chasing a $212,000 pay app runs six paragraphs: project history, relationship affirmations, three hedged references to 'cash flow considerations,' and finally the ask. Each round-trip gets longer and less effective.","task":"Rewrite it as a 3-sentence email: amount, days overdue, and what happens next.","tips":["Every hedge you cut raises the probability of payment.","'Cash flow considerations' is a euphemism — say 'we cannot fund your project's subs past the 30th.'","Length signals negotiability. Brevity signals a deadline."],"focus":["concision","impact"]},
    {"id":"concise-constr-senior-03","level":"senior","profession":"construction","title":"The weekly update on a diet","scenario":"Your weekly client update lists every trade's activity: 'Drywall continued on level 3. Painting continued on level 2. Electrical continued...' Eleven sentences of 'continued.' The two facts that matter: the elevator inspection passed, and tile is a week late.","task":"Write the update in 3 sentences that carry only what changed or needs attention.","tips":["'Continued as planned' for nine trades can be one sentence — or zero.","Lead with the two exceptions; that's what the reader scans for.","An update that reports everything gets read as nothing."],"focus":["concision","structure"],"placeholder":"Two things this week: the elevator passed inspection, and tile slipped a week."},
    {"id":"concise-constr-senior-04","level":"senior","profession":"construction","title":"Unhedging the schedule warning","scenario":"Your draft to the owner: 'I just wanted to flag that we may potentially be looking at some possible schedule pressure on the drywall front, which could conceivably have some impact on the overall timeline, in my opinion.' The truth: drywall is late and the date will move.","task":"Rewrite as one or two sentences that say what is actually happening.","tips":["Count the hedges: may, potentially, some, possible, conceivably, in my opinion — six in one sentence.","If the date is at risk, say which date and by how much.","Hedged warnings don't register; readers file them under 'fine.'"],"focus":["concision","precision"],"placeholder":"Drywall is two weeks late, which moves substantial completion to April 12 unless we add a crew."},
    {"id":"concise-constr-senior-05","level":"senior","profession":"construction","title":"The transmittal that says something","scenario":"Your transmittal letters open: 'Please find enclosed herewith the following documentation for your review and consideration at your earliest convenience.' Nobody has ever read that sentence. What matters: what's enclosed and what action you need by when.","task":"Write a 2-sentence transmittal body: what's attached, what you need, by when.","tips":["'Enclosed herewith' — pick one, or neither: 'Attached:'.","'For your review and consideration' hides the actual ask. Name it: approve, sign, comment.","Deadlines live in sentences people read — keep it to two."],"focus":["concision","clarity"]},
    {"id":"concise-constr-senior-06","level":"senior","profession":"construction","title":"The RFI without the essay","scenario":"Your project engineer drafted an RFI that runs 300 words: background, three drawing references, a site history, an apology for asking, and — somewhere — the question about the door hardware conflict. Architects answer short RFIs first.","task":"Cut the RFI to 3 sentences: the question, the reference, the date needed.","tips":["One RFI, one question — split compound questions into separate RFIs.","Apologizing for asking adds words and subtracts authority.","The answer-by date is the sentence most drafts forget."],"focus":["concision","precision"],"placeholder":"Which hardware set applies to door 214 — the schedule shows HW-3, the spec shows HW-5?"},
    {"id":"concise-constr-senior-07","level":"senior","profession":"construction","title":"Bid clarifications, stripped","scenario":"Your bid clarification list has grown defensive: 'The contractor has assumed, for the purposes of this proposal, that it is understood that winter conditions, if and where applicable, are excluded except as may be otherwise noted.' Estimators write these at midnight; lawyers read them in disputes.","task":"Rewrite the clarification in one clean sentence.","tips":["'It is understood that' and 'for the purposes of this proposal' protect nothing.","'If and where applicable' makes the exclusion arguable — precision protects, padding doesn't.","One sentence per exclusion, no compound qualifiers."],"focus":["concision","precision"],"placeholder":"Winter heating and hoarding are excluded."},
    {"id":"concise-constr-senior-08","level":"senior","profession":"construction","title":"The safety memo people will read","scenario":"Your safety coordinator's memo on the new harness rule runs a full page: regulatory background, incident statistics, the policy revision history, and finally the rule. Foremen will read the first two sentences at 6:45 a.m., standing up.","task":"Rewrite the memo as 3 sentences a foreman absorbs before the crew arrives.","tips":["Rule first, in operational words: who, what, where, starting when.","One sentence of why — the near-miss — makes it stick.","The regulatory background is a link, not a paragraph."],"focus":["concision","impact"],"placeholder":"Starting Monday: 100% tie-off above 3 metres, everywhere on site, no exceptions."},
    {"id":"concise-constr-senior-09","level":"senior","profession":"construction","title":"Cutting the proposal boilerplate","scenario":"Your proposals open with the same paragraph they've had for a decade: 'We are pleased to submit... full-service construction firm... commitment to excellence... exceeds expectations.' The selection committee reads forty of these. Yours says nothing they'll remember.","task":"Replace the boilerplate with 2 sentences of specific, verifiable claims about this project.","tips":["'Commitment to excellence' is a claim no one can check; 'three schools delivered early since 2023' is.","Write the sentence a committee member would quote in the scoring meeting.","Every generic phrase costs a specific one the space."],"focus":["concision","impact"]},
    {"id":"concise-constr-senior-10","level":"senior","profession":"construction","title":"The meeting minutes that decide","scenario":"Your coordination meeting minutes run four pages, transcribing discussion. Buried inside: three decisions and five action items with owners. The subs skim them, miss their actions, and next week's meeting repeats this one.","task":"Write the 3-sentence summary block you'd put at the top: decisions made, actions due, by whom.","tips":["Decisions and actions at the top; discussion below for the record.","One line per action: who, what, date. No narrative.","Minutes exist so next week's meeting is shorter, not longer."],"focus":["concision","structure"]},
    {"id":"concise-constr-senior-11","level":"senior","profession":"construction","title":"Nominalizations on the jobsite","scenario":"Your draft letter: 'The implementation of the remediation of the deficiencies will require the mobilization of additional resources and the coordination of multiple trades.' Every verb has been buried in a noun.","task":"Rewrite the sentence with people doing things, in 15 words or fewer.","tips":["'Implementation of the remediation' = 'fixing.' 'Mobilization of resources' = 'more crews.'","Find the actor: who fixes what, by when.","Buried verbs read as evasion — often because they are."],"focus":["concision","clarity"],"placeholder":"Fixing these deficiencies takes two extra crews working with three trades."},
    {"id":"concise-constr-senior-12","level":"senior","profession":"construction","title":"The redundant-pairs contract letter","scenario":"Your standard letters are full of legal-sounding pairs: 'null and void,' 'each and every,' 'due and payable,' 'terms and conditions,' 'any and all.' Some are contract terms; most are habit. A letter to the owner about backcharges is drowning in them.","task":"Rewrite this sentence cutting every redundant pair: 'Any and all backcharges shall be deemed due and payable upon each and every occurrence of the aforementioned conditions.'","tips":["'Any and all' = 'all.' 'Each and every' = 'each.' 'Aforementioned' = 'these.'","Keep a pair only if the contract defines it as a term of art.","Plain sentences get paid faster than ceremonial ones."],"focus":["concision","clarity"],"placeholder":"Backcharges are payable when these conditions occur."},
    {"id":"concise-constr-senior-13","level":"senior","profession":"construction","title":"The two-minute owner call","scenario":"You have the developer on the phone for two minutes between her meetings. You need: approval of CO-016, her equipment vendor's contact, and a heads-up that the crane comes down Saturday. Your habit is context first; her habit is hanging up on time.","task":"Script the call's first 3 sentences carrying all three items.","tips":["Number the items out loud: 'Three things, thirty seconds each.'","Ask items first, information items last — approvals need her; the crane doesn't.","If she extends the call, that's her choice; plan for two minutes."],"focus":["concision","structure"],"placeholder":"Three quick things. One: I need a yes on CO-016 today —"},
    {"id":"concise-constr-senior-14","level":"senior","profession":"construction","title":"Meta-commentary in the claim letter","scenario":"Your delay claim draft keeps narrating itself: 'As will be demonstrated below... It is important to note... As previously mentioned... The following section will address...' A quarter of the letter is announcements of the letter.","task":"Rewrite this passage without meta-commentary: 'It is important to note that, as will be demonstrated in the following sections, the delays in question were, as previously stated, beyond our control.'","tips":["Delete every sentence that describes the document instead of the delay.","'It is important to note that X' = 'X.'","Let headings do the navigating; let sentences carry facts."],"focus":["concision","clarity"],"placeholder":"The delays were beyond our control, as sections 3-5 show."},
    {"id":"concise-constr-senior-15","level":"senior","profession":"construction","title":"The site instruction, unpadded","scenario":"You're issuing a site instruction to the concrete sub to add dowels at the slab edge per the structural engineer's direction. Your draft wraps the instruction in three sentences of context and one of apology for the late notice.","task":"Write the instruction in 2 sentences: what to do, per what authority, effective when.","tips":["Instructions are not essays: action, reference, timing.","The apology belongs in a phone call, not the contractual record.","If it's compensable, say 'proceed and price it' — five words that prevent a fight."],"focus":["concision","precision"],"placeholder":"Add 15M dowels at 400mm o.c. at all slab edges on level 2, per SE sketch SK-14, before Thursday's pour."},
    {"id":"concise-constr-senior-16","level":"senior","profession":"construction","title":"Halving the warranty response","scenario":"Your office's standard warranty-response letter is 400 words: warranty philosophy, terms recap, exclusion caveats, scheduling logistics, and closing courtesies. Homeowners read it as evasive. The content is: we'll fix it, here's when, here's what we need from you.","task":"Rewrite the letter body in 3 sentences.","tips":["Commitment first: what you'll fix and the date.","One sentence of what you need: access, photos, a choice of morning.","Terms and exclusions only if they actually apply to this claim."],"focus":["concision","audience"]},
    {"id":"concise-constr-senior-17","level":"senior","profession":"construction","title":"The tender question, asked cleanly","scenario":"During tender you need to ask the owner's consultant whether the allowance for site servicing includes the offsite watermain tie-in — a $180,000 swing. Your draft question is three sentences of positioning before the question, which risks telegraphing your bid strategy anyway.","task":"Write the tender question in one sentence.","tips":["Naked questions reveal less than padded ones.","Name the document and section; ask the binary.","Every extra sentence is information your competitors get too — questions are shared."],"focus":["concision","precision"],"placeholder":"Does the site-servicing allowance in Section 01 21 00 include the offsite watermain tie-in?"},
    {"id":"concise-constr-senior-18","level":"senior","profession":"construction","title":"The apology that doesn't grovel","scenario":"Your crew damaged the client's existing lobby floor moving material — clearly your fault, about $8,000 to repair. Your draft apology is twelve sentences of remorse that never quite states the repair plan. Over-apology reads as instability; the client wants competence.","task":"Write a 3-sentence message: what happened, what you're doing about it, at whose cost.","tips":["One sentence of ownership beats five of remorse.","The repair plan and 'at our cost' are the apology.","End with prevention — the one change so it doesn't recur."],"focus":["concision","impact"],"placeholder":"We damaged the lobby terrazzo this morning moving drywall — that's on us."},
    {"id":"concise-constr-senior-19","level":"senior","profession":"construction","title":"Cutting the schedule narrative","scenario":"Your baseline schedule submission includes a narrative that restates the schedule in prose: 'Following the completion of foundations, structural steel erection will commence, after which...' Four pages retelling what the Gantt chart already shows.","task":"Write the 3 sentences the narrative should contain instead: the critical path, the two biggest risks, the decisions the schedule depends on.","tips":["Never narrate what the reader can see; add what they can't.","The critical path in one sentence: the chain that moves the end date.","Risks and owner-decision dates are the narrative's whole job."],"focus":["concision","structure"]},
    {"id":"concise-constr-senior-20","level":"senior","profession":"construction","title":"The invoice dispute reply","scenario":"The owner's consultant rejected $34,000 of your pay app with vague comments. Your drafted rebuttal is heated and long — two pages defending your firm's integrity. The effective reply is short: item, contract basis, evidence, resubmission.","task":"Write a 3-sentence rebuttal for one rejected line item.","tips":["Defend the line item, not your honour.","Cite the clause and the backup document by name; attach, don't argue.","Short and documented reads as confident; long and hot reads as worried."],"focus":["concision","precision"]},
    {"id":"concise-constr-senior-21","level":"senior","profession":"construction","title":"Trimming the recruitment ad","scenario":"Your job posting for a site superintendent is 600 words of responsibilities copied from an HR template. The three facts that attract the right person: the project ($30M industrial, greenfield), the autonomy (you run the site), the pay band. All three are buried or missing.","task":"Write the posting's first 3 sentences carrying those three facts.","tips":["Lead with the project — superintendents pick jobs, then employers.","'You run the site' in plain words beats twelve bulleted responsibilities.","Posting the pay band cuts your time-to-hire; vagueness costs candidates."],"focus":["concision","audience"]},
    {"id":"concise-constr-senior-22","level":"senior","profession":"construction","title":"The one-line daily to the owner","scenario":"The owner asked for a daily one-liner during the critical concrete week. Your superintendent's first attempt: 'Today we had some challenges with the pump but overall things went relatively well and we're more or less where we need to be.' Zero facts.","task":"Rewrite the daily as one sentence with the numbers that matter.","tips":["Cubic metres placed vs planned, plus tomorrow's risk — that's the whole genre.","'Relatively well' and 'more or less' are the enemy; say the number.","One precise sentence a day builds more trust than a weekly page."],"focus":["concision","precision"],"placeholder":"Placed 140 of 150 planned cubic metres (pump down 1 hr); on track to finish the pour tomorrow by noon."},
    {"id":"concise-constr-senior-23","level":"senior","profession":"construction","title":"The subcontract scope, deduplicated","scenario":"Your drywall subcontract scope has grown by accretion: 'Supply and install all drywall, including but not limited to supply of materials, installation of same, all labour required for installation...' The same obligation restated four ways invites the sub to argue about the differences.","task":"Rewrite the scope sentence once, cleanly, in under 20 words.","tips":["Say it once, completely; repetition creates ambiguity, not coverage.","'Including but not limited to' followed by restatements of the same thing protects nothing.","Specific inclusions earn their place; echoes don't."],"focus":["concision","precision"],"placeholder":"Supply and install all gypsum board assemblies per specification 09 21 16, including taping to Level 4 finish."},
    {"id":"concise-constr-senior-24","level":"senior","profession":"construction","title":"The escalation email to your own boss","scenario":"You need the company owner to approve hiring a claims consultant for the hospital dispute — $25,000, and worth it. Your draft is a defensive 500-word history of the dispute. He decides on: the exposure, the cost, the odds, and your recommendation.","task":"Write the request in 3 sentences: exposure, ask, and expected return.","tips":["He's deciding on a $25K spend against a $600K exposure — give him that ratio in sentence one.","Your recommendation is the point; the history is available on request.","Long justifications read like doubt. You don't doubt this."],"focus":["concision","impact"],"placeholder":"We have $600K at stake in the hospital claim, and I want to spend $25K on a claims consultant to protect it."},
    {"id":"concise-constr-senior-25","level":"senior","profession":"construction","title":"Cutting the walkthrough follow-up","scenario":"After the client walkthrough you drafted a follow-up email recapping the entire tour room by room. The client needs only: the six items you're fixing, the date they'll be done, and the one decision you need from them (the paint colour for the repaired wall).","task":"Write the follow-up in 3 sentences.","tips":["A numbered list of six fixes is one 'sentence' — use it.","Their one decision goes in its own sentence with a date.","Room-by-room recaps prove you were there; short lists prove you listened."],"focus":["concision","structure"]}
  ],
  "precision-and-evidence": [
    {"id":"precision-constr-senior-01","level":"senior","profession":"construction","title":"'Significant delay' means nothing","scenario":"Your delay notice says the watermain break caused 'significant delays to critical activities.' The owner's consultant will price 'significant' at zero. Your records show: 7 working days lost, excavation and forming idle, 4-person crew standing.","task":"Rewrite the sentence with the numbers, dates, and activities named.","tips":["'Significant' is an invitation to argue; '7 working days, March 3-11' is a fact.","Name the activities and the crew size — that's what gets priced.","Every vague word in a claim becomes a discount in the settlement."],"focus":["precision","impact"],"placeholder":"The break idled excavation and forming from March 3-11 — 7 working days — with a 4-person crew on standby."},
    {"id":"precision-constr-senior-02","level":"senior","profession":"construction","title":"'Costs have increased' — by what?","scenario":"Your escalation letter to a design-build client says 'material costs have increased substantially since our proposal.' You have the receipts: rebar up 11% ($42,000), lumber up 6% ($18,000), quotes attached. The letter uses none of it.","task":"Rewrite the sentence with the percentages, dollars, and evidence named.","tips":["Two specific numbers outperform one 'substantially.'","Cite the source: supplier quotes dated X vs Y — attach them.","Skeptic test: could the reader check every claim? If not, sharpen it."],"focus":["precision","clarity"],"placeholder":"Since our March proposal, rebar rose 11% ($42,000 on this job) and lumber 6% ($18,000) — supplier quotes attached."},
    {"id":"precision-constr-senior-03","level":"senior","profession":"construction","title":"The productivity report's one insight","scenario":"Your drywall productivity tracking shows: level 2 took 9 days, level 3 took 11, level 4 took 14, same crew, same scope per floor. You're reporting to your operations manager. The data means something: productivity is degrading about 20% per floor, and at this rate level 8 blows the schedule.","task":"Write the 2-sentence report: the one insight, then the number that proves it.","tips":["Don't hand over the table — hand over what the table means.","Project the trend forward: that's the insight that forces action.","One insight per report; the second-best finding dilutes the first."],"focus":["precision","impact"],"placeholder":"Drywall productivity is degrading about 20% per floor — at this rate level 8 alone takes 24 days and breaks the schedule."},
    {"id":"precision-constr-senior-04","level":"senior","profession":"construction","title":"What, So What, Now What: the weather log","scenario":"It rained 14 of the last 30 calendar days, versus a 10-year average of 8. You've logged it dutifully. The owner needs more than the log: what it did to the schedule, and what you're asking for.","task":"Write 3 sentences: What (the data), So What (the impact), Now What (the ask).","tips":["What: 14 rain days vs the 8-day average, with the source.","So What: which activities lost how many days.","Now What: the extension you're claiming and the notice this letter constitutes."],"focus":["precision","structure"],"placeholder":"We recorded 14 rain days in the last 30, against a 10-year average of 8 (Environment Canada, station 6158355)."},
    {"id":"precision-constr-senior-05","level":"senior","profession":"construction","title":"The skeptic-proof completion date","scenario":"You're about to commit a completion date to the owner's lawyer for the lease-driven project. Your draft says 'we anticipate completion in the fall.' Everyone downstream — tenant, lender, movers — will plan against whatever you write.","task":"Write the completion commitment in one sentence with the date, the definition, and the stated conditions.","tips":["'The fall' spans 90 days; a lease penalty accrues daily.","Define which completion: substantial performance, not final closeout.","Conditions must be verifiable events, not moods: permits by X, decisions by Y."],"focus":["precision","clarity"],"placeholder":"Substantial performance by October 17, conditional on owner colour selections by July 4 and no added scope after August 1."},
    {"id":"precision-constr-senior-06","level":"senior","profession":"construction","title":"The estimate range, honestly stated","scenario":"A repeat client wants a 'ballpark' for a warehouse addition before design exists. Whatever single number you say will be remembered as a quote. You know the honest answer is a range with named drivers.","task":"Write a 2-3 sentence answer that gives a defensible range and what moves it within that range.","tips":["A range with drivers is more precise than a false point estimate.","Name what moves it: soil conditions, clear height, fire suppression class.","State what the range excludes — that sentence is worth money later."],"focus":["precision","audience"],"placeholder":"Based on comparable jobs, $185-215 per square foot — the spread is mostly soils and clear height."},
    {"id":"precision-constr-senior-07","level":"senior","profession":"construction","title":"'The sub is behind' — show it","scenario":"You're documenting the mechanical sub's slippage for a potential termination. Your draft says they are 'consistently behind schedule and inadequately manned.' Your records: 4 missed milestones with dates, manpower averaging 6 against a committed 11.","task":"Rewrite the two claims with the evidence in the sentences.","tips":["Each adjective gets replaced by its number: 'inadequately manned' = '6 workers against the 11 committed.'","Milestones need dates: promised vs actual, listed.","Termination letters get read by judges; write for that reader."],"focus":["precision","impact"],"placeholder":"Since May 1 you have missed four milestones (list attached) and averaged 6 workers on site against the 11 committed in your baseline."},
    {"id":"precision-constr-senior-08","level":"senior","profession":"construction","title":"The concrete test result, interpreted","scenario":"The 28-day cylinder breaks came back: 24.1 MPa against a specified 25 MPa on one pour. You must tell the structural engineer and the owner. Your draft says 'results were slightly below specification but likely acceptable' — an opinion wearing a fact's clothes.","task":"Write 2-3 sentences separating the fact, the open question, and the action underway.","tips":["Fact: the number, the pour location, the spec value.","The acceptability call belongs to the engineer — frame it as the question you've asked them.","'Likely acceptable' from you is worth nothing and risks everything."],"focus":["precision","clarity"],"placeholder":"The level-3 slab broke at 24.1 MPa against a specified 25. We've asked the structural engineer to assess —"},
    {"id":"precision-constr-senior-09","level":"senior","profession":"construction","title":"Backcharge with a paper trail","scenario":"You're backcharging the plumbing sub $9,400 for the flood their uncapped line caused. Your draft says 'costs incurred as a result of your deficient work.' You have: the incident date, photos, the restoration invoice, 62 hours of your labour at contract rates.","task":"Write the backcharge notification in 2-3 sentences with every number sourced.","tips":["Itemize: restoration invoice $6,200, own forces 62 hrs @ $85 = $5,270 — wait, check your math before sending.","Attach the evidence and reference each piece.","A backcharge that arrives fully documented rarely gets fought."],"focus":["precision","impact"]},
    {"id":"precision-constr-senior-10","level":"senior","profession":"construction","title":"The 'percent complete' that means something","scenario":"Your pay app claims the electrical scope is '75% complete' and the owner's reviewer is pushing back. You know the real support: rough-in done on all floors (60% of value), devices on floors 1-3 of 6 (another 12%), panels terminated (3%).","task":"Write the 2-sentence justification tying the 75% to measurable, inspectable quantities.","tips":["Percent complete is an argument until it's a measurement.","Tie each slice to something the reviewer can walk out and see.","The schedule of values is your friend — cite its lines."],"focus":["precision","clarity"]},
    {"id":"precision-constr-senior-11","level":"senior","profession":"construction","title":"Vague specs cut both ways","scenario":"The spec says 'contractor shall repair damaged surfaces to match existing.' The owner now claims that includes repainting three entire corridor walls for one scuff each. You're writing the response that pins 'match existing' to something measurable.","task":"Write 2-3 sentences proposing a precise standard for the repair obligation.","tips":["Propose the test: viewed from 2 metres under normal lighting — an industry-standard formulation.","Offer the precise remedy: patch and paint corner-to-corner on the affected wall plane, not the corridor.","Whoever proposes the measurable standard usually gets it adopted."],"focus":["precision","impact"]},
    {"id":"precision-constr-senior-12","level":"senior","profession":"construction","title":"The bid comparison's real spread","scenario":"Three glazing bids: $840K, $890K, $1.02M. Your gut says take the low one, but the scopes differ: the low bid excludes engineering ($30K) and caulking ($25K), the middle carries both. You're writing the levelling summary for the owner.","task":"Write 2-3 sentences presenting the levelled numbers and the true low bidder.","tips":["Level first, compare second — raw bid totals mislead.","Show the arithmetic: $840K + $55K of exclusions = $895K levelled.","Name your recommendation from the levelled column, not the raw one."],"focus":["precision","structure"],"placeholder":"Levelled for scope, the bids are $895K, $890K, and $1.02M — the middle bid is the true low."},
    {"id":"precision-constr-senior-13","level":"senior","profession":"construction","title":"'As soon as possible' isn't a date","scenario":"You need the owner's tile selection to hold the schedule, and your draft asks for it 'as soon as possible.' Every undated request in this project's history has taken three weeks. The real requirement: selection by the 10th, or the bathrooms leave the critical sequence.","task":"Rewrite the request with the date and the specific consequence of missing it.","tips":["ASAP outsources the priority decision to the busiest person's inbox.","Date plus consequence: 'by the 10th, or bathrooms resequence and completion moves a week.'","If you can't name a consequence, maybe you don't need a deadline."],"focus":["precision","impact"],"placeholder":"We need your tile selection by June 10 — after that, bathrooms fall out of sequence and completion moves at least a week."},
    {"id":"precision-constr-senior-14","level":"senior","profession":"construction","title":"The equipment claim, quantified","scenario":"During the owner-caused suspension, your crane sat idle. Your draft claims 'standby equipment costs.' Your records: 15 working days, crane monthly rate $28,500, operator minimum call-outs, plus the rental company's letter confirming no offset work was available.","task":"Write the claim sentence with the daily rate arithmetic shown and the evidence cited.","tips":["Show the math in the sentence: monthly rate ÷ working days × idle days.","The no-mitigation letter is your best exhibit — cite it.","Auditable arithmetic settles; asserted totals litigate."],"focus":["precision","clarity"]},
    {"id":"precision-constr-senior-15","level":"senior","profession":"construction","title":"Safety stats without the fog","scenario":"Your annual safety summary for prequalification says 'we maintain an excellent safety record with continuous improvement.' The numbers: TRIF of 1.8 against an industry 3.2, zero lost-time in 14 months, but one serious near-miss last quarter.","task":"Write 2 sentences presenting the record with the actual numbers, including the honest caveat.","tips":["'Excellent' is graded by the reader; 1.8 vs industry 3.2 grades itself.","Include the near-miss and what changed — selective precision reads as spin.","Prequal reviewers reward auditable candour."],"focus":["precision","impact"],"placeholder":"Our recordable incident frequency is 1.8 against an industry average of 3.2, with no lost-time injuries in 14 months."},
    {"id":"precision-constr-senior-16","level":"senior","profession":"construction","title":"The schedule update, dated","scenario":"Your schedule narrative says the elevator installation 'is progressing well and should be complete soon.' The facts: cab 1 finished inspection Tuesday, cab 2 is 70% installed, completion forecast June 21, consultant's letter needed by June 14.","task":"Rewrite as 2 sentences with every 'soon' replaced by a date.","tips":["'Progressing well' + 'soon' = two facts withheld.","Include the dependency date — the consultant's letter — because that's the real risk.","Forecast dates can change; vague ones can't even do that."],"focus":["precision","concision"]},
    {"id":"precision-constr-senior-17","level":"senior","profession":"construction","title":"Pricing the acceleration, not describing it","scenario":"The owner asked what it costs to pull completion forward three weeks. Your draft says acceleration would involve 'substantial premium costs including overtime and additional supervision.' You've done the math: $118,000 — overtime premiums $64K, second shift supervision $22K, trade stacking inefficiency estimated at $32K.","task":"Write the answer in 2 sentences with the total, the breakdown, and the confidence level of each piece.","tips":["Lead with the total; itemize the three components.","Flag which number is firm and which is estimated — the stacking inefficiency is a judgment; say so.","'Substantial' invites haggling; $118K invites a decision."],"focus":["precision","clarity"],"placeholder":"Three weeks costs approximately $118,000: $64K overtime (firm), $22K added supervision (firm), $32K trade-stacking inefficiency (estimated)."},
    {"id":"precision-constr-senior-18","level":"senior","profession":"construction","title":"The deficiency described so it can be fixed","scenario":"Your deficiency notice to the glazing sub says 'various sealant deficiencies throughout the west elevation.' The sub's crew will wander, fix some, and claim completion. Your inspection found: failed adhesion at 14 identified joints, grid lines 3-8, levels 2-4, marked on the attached elevation.","task":"Rewrite the notice sentence so completion is verifiable.","tips":["'Various' and 'throughout' guarantee a second notice.","Count, locate, and reference the marked drawing.","Define done: reinspection of all 14 joints, together, on a named date."],"focus":["precision","impact"],"placeholder":"Sealant adhesion has failed at 14 joints, grid 3-8, levels 2-4, marked on the attached elevation —"},
    {"id":"precision-constr-senior-19","level":"senior","profession":"construction","title":"Cash flow, in actual weeks","scenario":"You're warning your business partner about a cash pinch. Your draft: 'Receivables are stretched and payables are coming due, so things will be tight for a while.' Reality: $410K in over-60-day receivables, $290K of sub payables due the 15th, line of credit $150K from its cap.","task":"Write the 2-sentence warning with the three numbers and the week the pinch peaks.","tips":["'Tight for a while' can't be acted on; 'the 15th, $290K due, $150K of room' can.","Name the action the numbers demand: draw the line, chase the two big receivables, or slow a payment.","Partners forgive bad numbers; they don't forgive foggy ones."],"focus":["precision","impact"]},
    {"id":"precision-constr-senior-20","level":"senior","profession":"construction","title":"What the moisture reading actually shows","scenario":"Before hardwood installation, your readings show subfloor moisture at 14% in the northeast corner against a manufacturer maximum of 12%; the rest of the floor reads 9-11%. Your flooring sub wants to install anyway. You're documenting your position to the client.","task":"Write 2-3 sentences: the readings, the standard, and your recommendation with its trade-off.","tips":["Readings with locations and the manufacturer's number — that's the whole argument.","Recommendation with the trade-off: wait 2 weeks, or install the dry zones now and hold the corner.","If it fails later, this email is the record — write it for that day."],"focus":["precision","structure"],"placeholder":"The northeast corner reads 14% moisture against the manufacturer's 12% maximum; the rest of the floor is 9-11%."},
    {"id":"precision-constr-senior-21","level":"senior","profession":"construction","title":"The land development number the buyer needs","scenario":"A developer asks what servicing the raw parcel will cost before they close. Your draft: 'servicing costs in the general range of typical suburban development.' Your actual estimate: $2.1-2.4M, with the storm outfall ($600K) and the intersection upgrade the city may require ($0-450K) as the swing items.","task":"Write the 2-sentence answer with the range and the two named swing items.","tips":["Their closing decision needs your two swing items more than your midpoint.","The maybe-required intersection is a discrete risk — give it as $0-450K, not blended in.","Say what would pin each number down: the city's response, the outfall survey."],"focus":["precision","audience"]},
    {"id":"precision-constr-senior-22","level":"senior","profession":"construction","title":"'Industry standard' won't survive the meeting","scenario":"You're defending your 8% overhead-and-profit markup on change orders, which the owner's auditor calls high. Your draft says 8% is 'industry standard.' Better evidence exists: it's the rate in the signed contract (GC 6.2), and it's below the 10% in two named public templates.","task":"Rewrite the defense in 2 sentences using the contract citation as the lead evidence.","tips":["The signed contract beats 'industry standard' every time — cite the clause.","The public templates are corroboration, named and checkable.","When you hold the strongest evidence, don't lead with the weakest."],"focus":["precision","impact"],"placeholder":"The 8% is the rate we both signed — GC 6.2 of the contract."},
    {"id":"precision-constr-senior-23","level":"senior","profession":"construction","title":"The punch item that keeps reopening","scenario":"The architect keeps reopening the 'door hardware adjustment' punch item with new comments each visit. You want it closed. Your draft complains the item 'keeps changing.' The record: original comment Oct 3, completed Oct 10, new scope added Oct 17 and Oct 31, each expanding the original.","task":"Write 2-3 sentences using the dated record to separate the original item from the added scope.","tips":["Dates turn a grievance into a boundary: completed Oct 10 as written.","Frame additions as new items — welcome, but new — potentially with cost.","Precision here isn't pedantry; it's how punch lists end."],"focus":["precision","structure"]},
    {"id":"precision-constr-senior-24","level":"senior","profession":"construction","title":"Manpower promised vs manpower real","scenario":"To win the recovery-plan approval, your draft promises 'significantly increased manpower.' The commitments you actually have in writing: drywall from 8 to 14 starting Monday, taping crew of 4 added Wednesday, painting double-shifted from the 20th.","task":"Rewrite the promise as the three dated, countable commitments.","tips":["'Significantly increased' will be graded against imagination; 14 workers gets graded against 14.","Dated commitments let the owner verify with one site visit — invite that.","Only promise the crews you have in writing from the subs."],"focus":["precision","impact"],"placeholder":"Drywall goes from 8 to 14 workers Monday, a 4-person taping crew joins Wednesday, and painting double-shifts from the 20th."},
    {"id":"precision-constr-senior-25","level":"senior","profession":"construction","title":"The final account, reconciled to the penny","scenario":"Closing out the contract, your final account letter says the balance owing is 'approximately $186,000 pending final adjustments.' The owner's accountant will not process 'approximately.' You have the arithmetic: contract sum, plus 16 COs, less payments to date, less holdback already released.","task":"Write the 2-sentence final-account statement showing the reconciliation chain.","tips":["Show the chain: original sum + COs − paid − released = balance. One line.","'Approximately' in a final account guarantees another 60 days of review.","Attach the CO log and payment register the chain references."],"focus":["precision","clarity"],"placeholder":"Final account: $4,212,000 original contract + $318,400 in 16 approved COs − $4,344,400 paid = $186,000 now due."}
  ],
  "executive-presence": [
    {"id":"presence-constr-senior-01","level":"senior","profession":"construction","title":"Own the foundation call","scenario":"Compressible fill means the developer must choose: piles, a raft slab, or over-excavate and re-compact. Your memo lays out all three with costs and stops there. The developer pays you for judgment, and a menu without a pick reads as ducking.","task":"Rewrite the close of the memo to state which option you recommend and why, in two sentences.","tips":["Name your pick in the first sentence, with the number attached.","Give the one trade-off you weighed — that shows the judgment, not just the answer.","Options are your analysis; the recommendation is what they're paying for."],"focus":["impact","clarity"],"placeholder":"I recommend piles at $410K — the raft saves $60K but puts settlement risk on a building you'll hold for twenty years."},
    {"id":"presence-constr-senior-02","level":"senior","profession":"construction","title":"Signpost the OAC meeting","scenario":"Your monthly owner-architect-contractor meetings run ninety minutes and the owner's rep says she can never tell where you are in the agenda or what actually needs deciding. Presence includes structure the room can hear.","task":"Write the three signpost sentences for the meeting: the opening frame, one transition, and the close.","tips":["Open with the shape: 'three items — schedule, cost, and one decision on the lobby stone.'","Announce each transition so nobody is lost: 'that's schedule; now cost.'","Close by restating the one decision you need and by when."],"focus":["structure","impact"],"placeholder":"Three things today: schedule, cost, and one decision I need from you on the lobby stone before we leave."},
    {"id":"presence-constr-senior-03","level":"senior","profession":"construction","title":"Fact versus judgment on the slip","scenario":"Your schedule brief to the developer blends what happened — the switchgear slipped four weeks at the factory — with what you think it means for completion. Mixed together, they can dispute your facts to dodge your judgment.","task":"Write two labeled lines: one stating only the facts, one stating your judgment and recommendation.","tips":["Facts are what the delivery notice says; judgment is what you conclude from it.","Label them so the reader can trust each separately.","A clean separation makes both harder to argue with."],"focus":["clarity","structure"],"placeholder":"Fact: switchgear delivery moved from Feb 3 to Mar 3, confirmed in writing by the supplier. Judgment: we can hold substantial completion if you approve overtime on electrical rough-in now."},
    {"id":"presence-constr-senior-04","level":"senior","profession":"construction","title":"The call against the pet feature","scenario":"The developer loves the cantilevered canopy — it's in every rendering. Your pricing says it's $290,000 of structural gymnastics on a building already over budget, and you believe it should go. Your draft hints at 'cost pressures' without saying so.","task":"Write the recommendation in one or two clear sentences, owning the unpopular call.","tips":["Hedging on a hard call costs more credibility than the call itself.","State it as your recommendation, not a question or a hint.","Pair it with what the money buys instead — that's the constructive half."],"focus":["impact","clarity"],"placeholder":"I recommend cutting the cantilevered canopy — it's $290K of structure for a gesture, and that money closes most of your budget gap."},
    {"id":"presence-constr-senior-05","level":"senior","profession":"construction","title":"Standing behind your number","scenario":"In the lender meeting you present the $1.2M cost-to-complete, then immediately add 'but construction is unpredictable, so who knows.' You watched the loan officer's confidence drain. The number is good — you built it line by line.","task":"Restate the estimate with ownership, acknowledging the real risk without disowning the number.","tips":["Own the number first; then bound the risk — don't dissolve the number into the risk.","'I'm confident in $1.2M; the one swing factor is winter conditions' shows command.","If you undercut your own estimate, the bank will discount it further for you."],"focus":["impact","precision"],"placeholder":"Cost-to-complete is $1.2M and I stand behind it — the one factor that could move it is a hard winter, and that's capped at about $80K."},
    {"id":"presence-constr-senior-06","level":"senior","profession":"construction","title":"Take command of the workout meeting","scenario":"The project is over budget and the bank called a meeting. Their analyst opens a spreadsheet and starts walking cells. If you follow their spreadsheet for an hour, you leave as the problem; if you frame the meeting, you leave as the solution. You get to speak first.","task":"Speak the opening 3 sentences that set the agenda: where the project stands, your plan, and what you need from the bank.","tips":["Frame the meeting before their spreadsheet does.","State the overrun yourself, plainly — owning it first buys the room.","End the opening on the specific thing you need the bank to approve."],"focus":["impact","structure"]},
    {"id":"presence-constr-senior-07","level":"senior","profession":"construction","title":"'I recommend' versus 'you could'","scenario":"Your value-engineering memo tells the owner they 'could consider' switching the curtain wall to window wall for a $340,000 saving. 'Could consider' commits you to nothing, and the owner has learned to ignore suggestions nobody stands behind.","task":"Rewrite the sentence as a first-person recommendation you own.","tips":["'You could consider' is a shrug; 'I recommend' is a position.","First person signals you'll be accountable for the outcome.","Owners fund recommendations, not considerations."],"focus":["impact","clarity"],"placeholder":"I recommend switching to window wall — it saves $340K and I've built it on three comparable towers without a leak."},
    {"id":"presence-constr-senior-08","level":"senior","profession":"construction","title":"The crisis briefing without panic","scenario":"A partial trench collapse stopped work this morning; no one was hurt, but the regulator is on site and the owner group wants a briefing at 2 p.m. Your draft notes read anxious — 'this is really bad', 'I'm very worried about the schedule.' They will take their temperature from yours.","task":"Write the 2-3 sentence opening of the briefing: honest about the seriousness, steady in tone, with the plan visible.","tips":["Name the seriousness as fact, not as your anxiety.","Lead with what's true and controlled: no injuries, site secured, regulator engaged.","Calm plus a plan is presence; worry without a plan is contagion."],"focus":["impact","audience"],"placeholder":"This morning we had a partial trench collapse — no one was hurt, the site is secured, and the regulator is on site with us now. Here is what happens next."},
    {"id":"presence-constr-senior-09","level":"senior","profession":"construction","title":"Owning the schedule miss","scenario":"Substantial completion slipped six weeks on your watch. Your draft to the developer spreads the causes across weather, the drywall sub, and permit delays — all true, all reading as excuses. The relationship survives ownership better than it survives explanations.","task":"Write a 2-3 sentence statement that owns the miss and states the fix, before any causes.","tips":["Own the result first; the shared causes read as blame-shifting until you do.","'I own this and here's what changes' beats any explanation.","Ownership is what buys you the room to present the recovery plan."],"focus":["impact","clarity"],"placeholder":"We're six weeks behind and that's mine to own — here's what I've changed so it doesn't slip again."},
    {"id":"presence-constr-senior-10","level":"senior","profession":"construction","title":"The menu with a pick","scenario":"The developer asked how to recover the schedule. You sent three options — overtime, a second crew, resequencing — each with cost and weeks saved, evenly weighted. She replied: 'Which one?' You did the analysis; you didn't do the job.","task":"Present the three options in one or two sentences each, but lead with and justify your recommended one.","tips":["Open with your pick and the trade-off you'd accept.","Then the other options in a line each, as context.","Show the map, point to the road."],"focus":["impact","structure"],"placeholder":"My recommendation is resequencing plus targeted overtime — $45K to recover four of the six weeks, without the quality risk of a green second crew."},
    {"id":"presence-constr-senior-11","level":"senior","profession":"construction","title":"Signposting the council case","scenario":"You have ten minutes in front of council on the lane-closure appeal, and your material is dense: crane engineering, pedestrian routing, schedule phasing. Last time, councillors interrupted with questions you were two slides from answering. They need to hear the structure.","task":"Write the opening signpost sentence that previews your three-part case.","tips":["Preview the shape: 'the need, the safety plan, and the shorter alternative we studied.'","Numbered parts let a lay audience hold a technical argument.","Signposting is confidence made audible — it says you know where this goes."],"focus":["structure","impact"],"placeholder":"I'll cover three things in ten minutes: why the closure is needed, how we keep pedestrians safe, and the shorter alternative we studied and why it fails."},
    {"id":"presence-constr-senior-12","level":"senior","profession":"construction","title":"Fact and judgment on the termination","scenario":"You're recommending the owner approve terminating the roofing sub for cause. Your memo mixes the documented failures — two missed cure deadlines, failed inspections — with your conclusion that they can't recover. The owner's lawyer needs to see evidence and opinion as separate things.","task":"Write two parts: the factual record in 1-2 sentences, then your judgment and recommendation in one.","tips":["Facts first, verifiable: dates, notices, inspection results.","Then the judgment, labeled as yours: they will not recover on this job.","The separation is what lets the lawyer act on it."],"focus":["clarity","impact"],"placeholder":"The record: cure notices issued May 2 and May 19, both deadlines missed, and the May 26 inspection failed on the same deficiencies. My judgment: they cannot staff this job, and I recommend termination for cause this week."},
    {"id":"presence-constr-senior-13","level":"senior","profession":"construction","title":"The confident 'I don't know yet'","scenario":"At the emergency meeting after the flood, the owner asks the total damage cost. You genuinely don't know — the drying contractor reports Thursday and the insurer hasn't scoped. Making up a number now will haunt every later conversation.","task":"Write a 2-sentence answer that owns not knowing while showing complete command of the path to knowing.","tips":["'I don't know yet' with a date beats a guess you'll have to walk back.","Say exactly when you'll know and what produces the number.","Composure about uncertainty is its own kind of presence."],"focus":["impact","clarity"],"placeholder":"I don't have a defensible number yet — I'll have one Friday, once the drying contractor's scope and the insurer's adjuster report are both in."},
    {"id":"presence-constr-senior-14","level":"senior","profession":"construction","title":"The strong close on the claim","scenario":"You just presented a well-documented $480,000 delay claim to the owner's team — forty minutes of evidence — and your draft ending is 'so, that's kind of where we landed, happy to discuss.' A mumbled close hands back everything the evidence earned.","task":"Write a closing 1-2 sentences that restate the claim and the specific next step you're asking for.","tips":["End on the ask, not a trail-off.","Restate the number so it's the last thing in the room.","Name the mechanism: a response by a date, a meeting, a referral to mediation."],"focus":["impact","clarity"],"placeholder":"The claim is $480,000, documented event by event, and I'm asking for your written response within 21 days per GC 8.3 — or a settlement meeting sooner, which I'd prefer."},
    {"id":"presence-constr-senior-15","level":"senior","profession":"construction","title":"The stop-work call is yours","scenario":"High winds are gusting past the crane's rated limit and picks are scheduled all afternoon. Your superintendent and the erector are debating; the owner's rep is asking about the schedule. Everyone is looking at you, and you catch yourself polling the room.","task":"Speak the decision in 1-2 sentences, owning the call rather than seeking consensus.","tips":["Consensus-seeking on a safety call is abdication — the accountable person decides.","State the decision and the trigger for resuming.","The schedule conversation happens after the decision, not instead of it."],"focus":["impact","clarity"],"placeholder":"We're standing down the crane now — no picks until sustained winds are back under the chart, and I'll make that call hourly."},
    {"id":"presence-constr-senior-16","level":"senior","profession":"construction","title":"Holding ground in the bid interview","scenario":"In the shortlist interview, the selection panel's construction advisor says your 14-month schedule 'can't be done' — the other bidders said 17. Your schedule is real: you've built the same structure type twice at this pace, and your logic ties to a crane and formwork strategy the others don't have.","task":"Speak a 2-3 sentence response that holds your position with evidence, without defensiveness or retreat.","tips":["Acknowledge the challenge, then stand on the specifics.","Name the two proof points: the comparable projects and the method that makes it work.","Folding under pressure loses the job as surely as arrogance does."],"focus":["impact","precision"]},
    {"id":"presence-constr-senior-17","level":"senior","profession":"construction","title":"Name the risk before they do","scenario":"You're presenting your proposal for a school addition that must finish before September. The real risk is the spring thaw hitting sitework. If the panel raises it first, you're defending; if you raise it, you're the one who saw it coming.","task":"Write the 2-3 sentences that name the biggest risk and own the mitigation, for the proposal.","tips":["Naming the risk first disarms the room and marks you as the realist.","Pair it immediately with the mitigation and its trigger date.","Owning risk with a plan reads as more competence than claiming none exists."],"focus":["impact","precision"],"placeholder":"The one risk that threatens September is the spring thaw hitting our sitework window — so we've fronted all underground work into the fall and hold a two-week weather buffer we don't touch."},
    {"id":"presence-constr-senior-18","level":"senior","profession":"construction","title":"The room after the lost anchor job","scenario":"Your firm just lost the $22M hospital bid that half the office spent the winter chasing, and word is already around. You're gathering the team at 4 p.m. Your draft notes are apologetic and small. Twenty people are about to read the company's future off your posture.","task":"Speak the opening 3 sentences: honest about the loss, steady, and pointed at what's next.","tips":["Acknowledge the loss plainly — pretending it's fine insults their effort.","Then set the temperature: the pipeline, the next pursuit, what the bid taught you.","They need direction from you more than they need contrition."],"focus":["impact","audience"]},
    {"id":"presence-constr-senior-19","level":"senior","profession":"construction","title":"Against the developer's instinct","scenario":"The developer wants to mobilize before the building permit is issued — 'it's basically approved, and we're burning weeks.' You've seen plan review surprise people, and unpermitted work risks a stop-work order and the lender's trust. Agreeing is easy; it's also wrong.","task":"Write a 2-3 sentence response that respectfully disagrees, owns your view, and offers the alternative.","tips":["Respectful disagreement is presence; silent agreement you don't believe is not.","Name the specific downside: a stop-work order costs more weeks than you'd save.","Offer what you can do now — early procurement, site prep under separate permit."],"focus":["impact","clarity"],"placeholder":"I'd counsel against mobilizing before the permit — a stop-work order costs us more than the two weeks we'd save, and it lands on your lender's desk. What I can do now is release the long-lead orders and fence the site."},
    {"id":"presence-constr-senior-20","level":"senior","profession":"construction","title":"Purge the hedge words","scenario":"Your delay claim letter is riddled with 'we feel', 'it seems that', and 'we would suggest that perhaps' — language your lawyer says reads like you don't believe your own claim. The facts are strong; the words are weak.","task":"Rewrite this sentence without hedges: 'We feel that it seems the owner's late steel decision may have possibly impacted our schedule.'","tips":["Facts don't feel — state what the record shows.","One qualifier maximum, and only where genuine uncertainty exists.","Weak language invites a weak settlement."],"focus":["precision","impact"],"placeholder":"The owner's steel decision, issued 23 days late on March 14, delayed structural steel start by 19 working days."},
    {"id":"presence-constr-senior-21","level":"senior","profession":"construction","title":"The contingency draw without apology","scenario":"You need to draw $85,000 from the project contingency for the rock excavation — exactly what contingency exists for. Your draft email to the owner reads like a confession, and an apologetic tone will teach them to treat every draw as a failure.","task":"Write a 2-3 sentence notification that presents the draw as managed risk, not fault.","tips":["Contingency spent on its intended purpose is the plan working, not failing.","State the draw, the cause, and the remaining balance in a level voice.","Apologizing for proper process invites challenges to proper process."],"focus":["impact","audience"],"placeholder":"We're drawing $85,000 from contingency for the rock encountered at grid line 4 — this is what the fund is for. Remaining balance is $215,000 against a project that is 45% complete, which is healthy."},
    {"id":"presence-constr-senior-22","level":"senior","profession":"construction","title":"Set the agenda with the architect","scenario":"Design coordination calls with the architect's office meander for an hour and end without decisions, and your RFI log is growing. You've been letting their junior run the call. This week, you open it.","task":"Write your opening 2 sentences that assert what the call is for and what must be decided before it ends.","tips":["Name the decisions, not the topics: 'we leave this call with answers on three RFIs.'","Attach a consequence to each: which trade stops without it.","Whoever frames the meeting owns the meeting."],"focus":["structure","impact"],"placeholder":"We need three decisions before we hang up: RFI-041, 044, and 047 — each one is holding a trade as of Monday."},
    {"id":"presence-constr-senior-23","level":"senior","profession":"construction","title":"Defending the fee once","scenario":"In the final account negotiation, the owner's cost consultant attacks your general conditions and fee percentage for the third time, hoping repetition wears you down. Your basis is sound: it's the contract rate, applied correctly. Re-arguing it each time signals it's negotiable.","task":"Write the 1-2 sentence response that states the basis once, with finality but without heat.","tips":["State the contractual basis and the arithmetic — once, completely.","Then stop; re-justifying signals the number is soft.","Calm repetition of the same answer is stronger than a new argument each round."],"focus":["precision","impact"],"placeholder":"The fee is 5% applied to the adjusted contract sum, per Schedule B — the same basis as all sixteen approved change orders. That figure won't move."},
    {"id":"presence-constr-senior-24","level":"senior","profession":"construction","title":"A date with a spine","scenario":"The owner asks for the completion date and you hear yourself say 'hopefully sometime in late spring, if things go okay.' Mush. The honest answer is a date plus one named risk — that's calibrated confidence, and it's what an owner can actually plan around.","task":"Write a 1-2 sentence answer that gives a firm date and bounds the one real risk.","tips":["Give the date first, plainly.","Name the single factor that could move it and by how much.","'May 15, with a two-week risk on elevator inspection' beats 'hopefully spring' every time."],"focus":["precision","clarity"],"placeholder":"Substantial completion is May 15. The one risk to it is elevator inspection scheduling, and that's a two-week swing at most."},
    {"id":"presence-constr-senior-25","level":"senior","profession":"construction","title":"The letter the surety reads twice","scenario":"Your bonded project is in trouble — the owner is slow-paying and you may need to signal a dispute. Anything you write to your surety gets read as either panic or command, and panic invites them to manage you. The facts are manageable; the letter has to sound like you are managing them.","task":"Write the 2-3 sentence opening of the letter to your surety: factual, steady, and clear about what you're doing.","tips":["Lead with the situation stated as fact, without alarm words.","Show the plan already in motion — notices issued, meetings set.","Tell them what you need from them, even if it's 'nothing yet, this is notification.'"],"focus":["audience","impact"],"placeholder":"I'm writing to keep you informed ahead of any noise: the owner on the Fairview project is 68 days behind on payment, we've issued notice under GC 5.4, and a resolution meeting is set for the 12th. No action is needed from you at this time."}
  ],
  "answering-under-pressure": [
    {"id":"pressure-constr-senior-01","level":"senior","profession":"construction","title":"'Will you make the date?'","scenario":"The developer opens the call with one question: 'Will you hit June 30, yes or no?' The honest answer is yes-with-one-risk. Your instinct is to walk through the schedule history first, which he will hear as a no being warmed up.","task":"Write your first two sentences: the direct answer, then the one risk.","tips":["Answer the question asked — yes, no, or the specific risk — in sentence one.","Context comes after the answer, never instead of it.","A direct answer with a named risk builds more trust than an unqualified yes."],"focus":["clarity","impact"],"placeholder":"Yes — June 30 holds. The one thing that could move it is the elevator inspection, and I'll know by the 10th."},
    {"id":"pressure-constr-senior-02","level":"senior","profession":"construction","title":"The contingency question at the bank","scenario":"At the site meeting, the lender's inspector asks in front of everyone: 'Why is half the contingency gone at 40% complete?' There's a good answer — the rock CO consumed most of it, and the remaining risk profile is lower — but a defensive ramble will read as trouble.","task":"Write a 2-3 sentence answer: direct, numbers first, defensiveness nowhere.","tips":["Answer with the arithmetic: what consumed it and what risk remains.","The second half of the answer is why the remaining balance is adequate — that's their real question.","Steady beats fast; take one breath before the numbers."],"focus":["clarity","precision"],"placeholder":"One event took it: the rock at grid 4 consumed $85K of the $150K spent. The remaining $150K covers a back half with far less ground risk — the shell is up."},
    {"id":"pressure-constr-senior-03","level":"senior","profession":"construction","title":"The hostile council question","scenario":"At the public hearing, a councillor leans in: 'Why should my constituents put up with two years of your trucks?' The gallery is full of those constituents. A technical answer about haul routes loses the room; so does anything that sounds like the neighbourhood is a nuisance to your schedule.","task":"Speak a 2-3 sentence answer that respects the concern, gives the real commitment, and stays calm.","tips":["Validate the cost to residents before defending anything — it's real.","Give the specific commitments: hours, routes, the phone number a human answers.","You're answering the gallery, not just the councillor."],"focus":["audience","impact"]},
    {"id":"pressure-constr-senior-04","level":"senior","profession":"construction","title":"'What's the total damage?'","scenario":"Your custom-home client, mid-overrun, stops you in the driveway: 'Just tell me — what is this house actually going to cost me?' The honest number is $1.34M against the $1.25M contract, driven by their upgrades plus the two site conditions. They deserve the number, not a process answer.","task":"Write the 2-sentence answer: the number first, then the one-line breakdown.","tips":["Give the number in the first breath — hedging now costs the relationship more than the overrun.","One sentence of breakdown: their choices versus site conditions.","Offer the line-by-line review after the headline, not instead of it."],"focus":["clarity","precision"],"placeholder":"All-in, you're landing at about $1.34M. Roughly $60K of that is upgrades you chose, and $30K is the two site conditions — I'll walk you through every line tonight if you want."},
    {"id":"pressure-constr-senior-05","level":"senior","profession":"construction","title":"'I don't know' in front of the owner","scenario":"In the coordination meeting, the architect asks whether the transfer beam can take the new rooftop unit load. You don't know — that's a structural engineer's answer — and the owner is watching. Bluffing a guess about structure is how buildings and careers fail.","task":"Write the 2-sentence answer that owns not knowing and commits to the path and date.","tips":["'I don't know' on a structural question is the only professional answer.","Attach the path: who answers it and by when.","Never guess about structure to save face in a meeting."],"focus":["clarity","impact"],"placeholder":"That's not mine to guess — it's a structural question. I'll have the engineer's answer in writing by Thursday, and nothing goes on that roof until we do."},
    {"id":"pressure-constr-senior-06","level":"senior","profession":"construction","title":"Answer only what was asked","scenario":"In mediation over the delay claim, the owner's lawyer asks: 'Did your crew work the week of March 10?' The answer is no — because the site was flooded, which is the whole point of your claim. But volunteering three paragraphs to a yes/no question is how lawyers collect ammunition.","task":"Write the disciplined 1-2 sentence answer: the fact asked for, plus only the clause that protects it.","tips":["Answer the question asked, precisely, and stop.","One protective clause is allowed: 'No — the site was under water.'","Over-answering under examination hands the other side its next question."],"focus":["precision","concision"],"placeholder":"No — the site was flooded that week and inaccessible, which is documented in the daily logs."},
    {"id":"pressure-constr-senior-07","level":"senior","profession":"construction","title":"'You should have foreseen this'","scenario":"You present the rock change order and the owner's rep fires back: 'A competent contractor would have foreseen this.' The geotech report — commissioned by the owner — showed no rock at that depth. The facts are on your side; the temptation is to get hot.","task":"Write a 2-3 sentence response that answers the challenge with the record, not with heat.","tips":["Answer the accusation with the document, not with indignation.","'The owner's own geotech report shows...' is more devastating calm than loud.","End by returning to the ask: the CO and its date."],"focus":["impact","precision"],"placeholder":"We priced from the geotech report your team commissioned, and boring logs B-3 and B-4 show no rock above 6 metres. Nobody could have foreseen this — that's why the contract puts subsurface risk where it puts it. I still need the CO signed by Friday."},
    {"id":"pressure-constr-senior-08","level":"senior","profession":"construction","title":"The reporter at the fence","scenario":"After the trench collapse, a reporter catches you at the site gate: 'Workers are saying this site cuts corners — your response?' Anything defensive becomes the headline. You have a good record and a real answer, and you get one sentence before she stops listening.","task":"Write the one-sentence answer, plus one background sentence.","tips":["Lead with the human fact: everyone went home safe, and the regulator is on site with your cooperation.","Never repeat the accusation — 'we don't cut corners' prints as 'contractor denies cutting corners.'","Give her the quotable sentence you want printed."],"focus":["audience","concision"],"placeholder":"Every worker went home safe today, and we're working side by side with the regulator to understand exactly what happened — that's how this site runs."},
    {"id":"pressure-constr-senior-09","level":"senior","profession":"construction","title":"'Why should we believe this schedule?'","scenario":"You're presenting the recovery schedule to a developer you've already missed one date for. He cuts in: 'You said the same thing in March. Why is this one real?' It's the right question, and it deserves a real answer — what's different — not a louder promise.","task":"Write a 2-3 sentence answer naming what's structurally different this time.","tips":["Don't re-promise harder; show what changed — bought materials, a second crew, float restored.","Acknowledge the miss in one clause; spend the sentences on the mechanics.","Offer the verification: weekly look-ahead they can check themselves."],"focus":["impact","precision"],"placeholder":"Fair question — March slipped because we were waiting on materials that are now on site and paid for. This schedule has the switchgear in our warehouse, a second drywall crew signed, and two weeks of float we didn't have before, and you'll see it verified in a weekly look-ahead."},
    {"id":"pressure-constr-senior-10","level":"senior","profession":"construction","title":"The failure question, answered straight","scenario":"The selection panel for the museum project asks: 'Tell us about a project that went badly and what you did.' Every instinct says spin. The panel has seen your litigation history — they're testing honesty, not perfection. You have a real answer: the 2021 warehouse job.","task":"Speak the 3-sentence answer: the failure named plainly, the cause, and what changed in your firm because of it.","tips":["Name a real failure with a number — a sanitized non-answer fails the actual test.","One sentence of cause, without blaming others.","Land on the durable change: the process that exists now because of it."],"focus":["structure","impact"]},
    {"id":"pressure-constr-senior-11","level":"senior","profession":"construction","title":"The blow-up at the trailer","scenario":"The mechanical sub's owner storms into your site trailer, voice raised, in front of your coordinator: 'You're strangling me with paperwork and my guys walk today.' Matching his volume escalates; folding rewards the outburst. There's a real issue under it — his payment is 20 days late through the owner's slow certification.","task":"Speak your first two sentences: lowered temperature, the real issue named, next step in private.","tips":["Drop your volume as his rises — it's the only move that de-escalates.","Name the legitimate issue under the anger; it tells him you actually heard.","Move the negotiation out of the audience: 'walk with me.'"],"focus":["audience","clarity"],"placeholder":"You're right that the payment is late, and that's worth being angry about — walk with me and I'll show you exactly where it's stuck and what I'm doing about it today."},
    {"id":"pressure-constr-senior-12","level":"senior","profession":"construction","title":"'Is my house safe?'","scenario":"After the failed framing inspection, the owner calls, voice shaking: 'Just answer me — is the house safe?' The answer is yes: the flagged items are code compliance details, not structural danger, and they'll be fixed before anything is covered. She needs the direct answer before any explanation survives.","task":"Write the 2-sentence answer: the direct yes with its basis, then the fix.","tips":["Answer the fear in the first three words.","Then one sentence of basis — what the items are and aren't.","Explanation before the answer reads as evasion to a frightened owner."],"focus":["clarity","audience"],"placeholder":"Yes — your house is safe. The two flagged items are spacing details the code requires, not signs of a problem, and both get fixed and reinspected before we close a single wall."},
    {"id":"pressure-constr-senior-13","level":"senior","profession":"construction","title":"The three-part question","scenario":"The developer's board member asks in one breath: 'Where's the budget, when do we open, and why did the facade cost move?' Answering in a tangle loses all three. Pressure rewards the person who can hear the structure inside the question.","task":"Write the answer as three labeled beats, one sentence each, in the order asked.","tips":["Repeat the structure back: 'Budget, date, facade — in that order.'","One sentence per part; depth on request.","Answering in their order tells them you actually listened."],"focus":["structure","clarity"],"placeholder":"Three answers. Budget: trending $120K over, contained by contingency. Opening: October 1, unchanged. Facade: the aluminum tariff moved it $45K, and I have a substitution that claws back $30K if you want it."},
    {"id":"pressure-constr-senior-14","level":"senior","profession":"construction","title":"'Your fee seems rich'","scenario":"During contract negotiation, the owner slides your fee breakdown across the table: 'Five percent on top of general conditions — justify that.' A defensive posture concedes the frame that the fee needs defending. The fee pays for the thing they're actually buying: a building that finishes.","task":"Write a 2-3 sentence answer that reframes the fee as what it buys, with one comparison that lands.","tips":["Don't itemize apologetically — state what the fee carries: risk, warranty, the balance sheet behind the bond.","One comparator: what a cheaper GC's failure costs against the fee difference.","Confidence about your price is part of what they're buying."],"focus":["impact","audience"],"placeholder":"The five percent is what stands behind the building: the bond, the warranty, and a firm that's still here in year five. The gap between my fee and the low bidder's is about $90K — one bad month with a failing GC costs more than that."},
    {"id":"pressure-constr-senior-15","level":"senior","profession":"construction","title":"'When did you know?'","scenario":"The owner, angry about the late-announced delay, asks the dangerous question: 'When did you actually know the date was gone?' The honest answer is three weeks ago — you spent two of those verifying before raising the alarm. Fudging the timeline now converts a schedule problem into a trust problem.","task":"Write a 2-3 sentence answer with honest dates and the reason for the gap.","tips":["Give the real dates — this question is usually already answered in your emails.","Explain the gap as verification, if that's true: 'I don't raise alarms I haven't confirmed.'","A clean answer here ends the interrogation; a fudged one starts discovery."],"focus":["precision","clarity"],"placeholder":"I saw the first signal three weeks ago when the fabricator missed their milestone, and I spent two weeks confirming it was real before bringing you a verified date instead of a scare. In hindsight I'd give you the early signal too — and going forward I will."},
    {"id":"pressure-constr-senior-16","level":"senior","profession":"construction","title":"The question you can't answer","scenario":"At the industry dinner, a friendly competitor asks how the arbitration with your former client is going. It's active litigation; anything you say can surface. But a cold 'no comment' among peers reads as guilt or panic.","task":"Write the 1-2 sentence graceful decline that neither stonewalls nor leaks.","tips":["Name the reason plainly — 'it's in arbitration, so I can't discuss it' is respected, not suspicious.","Offer what you can say: you're confident in your position and it'll resolve.","Then move the conversation; don't linger in the vacuum."],"focus":["precision","audience"],"placeholder":"That one's in arbitration, so I genuinely can't get into it — I'll just say I'm comfortable with our position. How's your hospital job treating you?"},
    {"id":"pressure-constr-senior-17","level":"senior","profession":"construction","title":"Interrupted by the CFO","scenario":"Four slides into your progress presentation, the developer's CFO cuts in: 'Stop — just tell me if we're calling more capital or not.' The full answer is on slide nine. The room is watching whether you can leave your script.","task":"Speak the 2-sentence response: answer the interruption now, then offer the path back.","tips":["Answer the question immediately — the deck serves you, not the reverse.","Then offer the supporting detail: 'the bridge to that number is three slides — want it?'","Flexibility under interruption is the competence being tested."],"focus":["structure","impact"]},
    {"id":"pressure-constr-senior-18","level":"senior","profession":"construction","title":"The inspector's challenge","scenario":"The building inspector, on site and skeptical, says your fire-stopping doesn't match the listed assembly. You believe it does — you have the ULC listing and the installer's certification in the trailer. Arguing on the spot antagonizes the person who signs your occupancy permit.","task":"Write your 2-sentence response: respectful, factual, and pointed at the documents rather than a debate.","tips":["Never argue from memory with an inspector — move to the documents.","'Let me pull the listing — if we're off, we'll fix it' costs nothing and wins either way.","The relationship outlasts this inspection; the tone is the investment."],"focus":["precision","clarity"],"placeholder":"Let me pull the ULC listing and the installer's cert from the trailer so we're both looking at the same sheet — and if the install is off the listing anywhere, we'll make it right before you're back."},
    {"id":"pressure-constr-senior-19","level":"senior","profession":"construction","title":"'Guarantee me it won't slip again'","scenario":"After the recovery plan presentation, the owner says: 'I want your personal guarantee this date won't move.' No honest builder can guarantee weather, inspectors, and supply chains — but 'I can't guarantee anything' sounds like the date is soft. The real answer is what you control and what you'll commit to.","task":"Write a 2-3 sentence answer that declines the false guarantee and offers the real commitment.","tips":["Refuse the impossible promise plainly — a false guarantee is a future broken promise.","Commit to what you control: buffers held, escalation within 24 hours of any signal.","Specific commitments are more reassuring than absolute ones."],"focus":["clarity","impact"],"placeholder":"I won't give you a guarantee I can't stand behind — nobody controls the weather or the inspection desk. What I will commit to: two weeks of protected float, and if anything threatens the date you hear it from me within 24 hours, with a fix attached."},
    {"id":"pressure-constr-senior-20","level":"senior","profession":"construction","title":"The wrong-premise question","scenario":"The owner's board member opens with: 'Given that you're two months behind, why shouldn't we replace you?' You're three weeks behind, not two months — the premise is wrong, and answering the question as asked accepts it. Correcting angrily loses the room; not correcting loses the facts.","task":"Write a 2-sentence response: fix the premise calmly, then answer the real question.","tips":["Correct the fact first, briefly and without triumph.","Then answer the legitimate question underneath: why you're still the right builder.","Accepting a false premise haunts every later negotiation."],"focus":["precision","clarity"],"placeholder":"One correction first: we're three weeks behind, not two months — the recovery schedule in front of you shows the path back. On the real question: replacing a GC mid-structure costs a season and a re-mobilization premium, and here's why you won't need to."},
    {"id":"pressure-constr-senior-21","level":"senior","profession":"construction","title":"The hypothetical trap","scenario":"In the dispute meeting, the owner's lawyer muses: 'What if we simply hired another contractor to finish the deficiencies and back-charged you?' It's a pressure move dressed as a question. The contract requires notice and opportunity to cure, and rising to the threat concedes the frame.","task":"Write a 2-sentence answer that treats the hypothetical calmly and restates the contractual path.","tips":["Answer the hypothetical as procedure, not as threat: 'the contract sets out how that works.'","Restate your position: cure list, dates, crew scheduled.","Calm procedural answers defuse theatrical questions."],"focus":["impact","precision"],"placeholder":"The contract covers that path — it requires written notice and a cure period first, and our crew is scheduled against the deficiency list for Monday. The fastest way to a finished building is the crew that's already mobilized."},
    {"id":"pressure-constr-senior-22","level":"senior","profession":"construction","title":"The rapid-fire complaint call","scenario":"The new homeowner calls with eleven complaints in ninety seconds: paint, a sticking door, the driveway slope, a missing screen, and on. Answering each in the order fired guarantees a chaotic call. One of the eleven — water pooling at the foundation — actually matters today.","task":"Write your 2-3 sentence response: triage stated out loud, the urgent item answered, the rest structured.","tips":["Say the triage: 'one of these is urgent, and I'm on it first.'","Answer the urgent one with an action and a day.","Convert the rest into a process: written list, one walkthrough, one fix visit."],"focus":["structure","concision"],"placeholder":"One of those matters today — the water at the foundation, and I'll have someone there tomorrow morning to check the grading. For the other ten, email me the full list and we'll book a single walkthrough Friday and fix them in one visit."},
    {"id":"pressure-constr-senior-23","level":"senior","profession":"construction","title":"'Why are you $400K higher?'","scenario":"The developer calls after bid opening: 'You're $400K over the low bid. Give me one reason not to sign with them.' You've seen the low bidder's work — and their exclusions list. This is a real question with a real answer, and you get about three sentences of his attention.","task":"Write the 3-sentence answer: where the $400K lives, what the low bid excludes, and what you carry that they don't.","tips":["Don't trash the competitor — dissect the number instead.","Name the exclusions and allowances in the low bid that converge on your price by month six.","End with the thing money can't add later: your team, your schedule record."],"focus":["impact","precision"],"placeholder":"Most of that $400K is in their exclusions — winter conditions, traffic control, and a $200K site-services allowance that history says doubles. Priced apples to apples, the gap is under $100K, and that buys you the team that's finished its last six jobs on the promised date."},
    {"id":"pressure-constr-senior-24","level":"senior","profession":"construction","title":"The safety question you knew was coming","scenario":"In the interview for the school board project, a trustee asks about the scaffold fall on your site last year. It's public record; they're watching how you carry it. Minimizing it fails; wallowing fails. Own it, state what changed, offer the evidence.","task":"Write the 3-sentence answer: ownership, the specific changes, and the verifiable result since.","tips":["Own it without qualifiers in sentence one — 'a worker was hurt on my site.'","Name the concrete changes: third-party audits, the harness policy, the retraining.","Close with the measurable since: incident-free hours, audit scores they can check."],"focus":["impact","clarity"],"placeholder":"A worker was seriously hurt on my site last March, and I own that completely. We rebuilt our fall-protection program around third-party audits and a hard 100%-tie-off rule, and we're 400,000 hours without a lost-time incident since — the audit reports are available to this board."},
    {"id":"pressure-constr-senior-25","level":"senior","profession":"construction","title":"The same question, third time","scenario":"For the third time this meeting, the owner asks whether the project can finish by August instead of October — hoping repetition produces a different answer. It can't, not safely. Irritation loses the relationship; a softer answer the third time loses the truth.","task":"Write the 2-sentence answer that holds the same position with patience and closes the loop.","tips":["Same answer, same numbers, warmer delivery — consistency is the message.","Name what would have to be true for August, so the no has a shape.","Then close the topic: 'if that changes, you'll hear it from me first.'"],"focus":["clarity","impact"],"placeholder":"It's still October — August would require the permit in hand today and a curtain wall crew that doesn't exist in this market. If either of those changes, you'll hear it from me the same day."}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-constr-senior-01","level":"senior","profession":"construction","title":"The design-build before/after","scenario":"You're pitching a developer on design-build delivery instead of the traditional bid they've always used. Your draft lists features of design-build. What persuades is contrast: their last project's change-order war versus a single point of accountability.","task":"Write a 3-sentence pitch framed as before/after: where their last project hurt, where this one lands, and the bridge.","tips":["Persuasion lives in contrast — name the pain they already felt.","Paint the after in their terms: one contract, one throat to choke, price certainty earlier.","The bridge is the ask: let us take single-point responsibility on this one."],"focus":["impact","structure"],"placeholder":"On your last project, 340 RFIs and $1.1M in change orders came from the gap between designer and builder — under design-build, that gap is my problem, not yours."},
    {"id":"narrative-constr-senior-02","level":"senior","profession":"construction","title":"Make the envelope stakes human","scenario":"The condo board is deferring the $600,000 building-envelope repair for the third year because the numbers feel abstract. The stakes aren't abstract: water is in two units already, and every deferred year compounds the scope. Data hasn't moved them; consequence might.","task":"Write a 2-3 sentence appeal that makes the stakes concrete and human, not actuarial.","tips":["Trade the spreadsheet for the specific: unit 411's bedroom wall, this winter.","Name the compounding: what $600K becomes at year five.","End with the decision framed as protection, not expense."],"focus":["impact","audience"],"placeholder":"Water is already inside unit 411's bedroom wall — that's what year three of deferral looks like. At year five, this is a $1.4M recladding instead of a $600K repair, and the board that deferred it will be the story every owner tells."},
    {"id":"narrative-constr-senior-03","level":"senior","profession":"construction","title":"Disarm the price objection first","scenario":"Your tender cover letter for the library project is strong on qualifications, but you know exactly what the committee will say in the room: 'they're not the cheapest.' If the letter doesn't answer that objection, the low bidder's number answers it for you.","task":"Write the 2-3 sentences of the letter that raise and answer the price objection before the committee does.","tips":["Name the objection yourself — it disarms the room and marks you honest.","Reframe: the gap between bids is a fraction of the cost of a project that goes wrong.","Give the evidence: your last five projects' final cost versus contract."],"focus":["impact","structure"],"placeholder":"You'll notice we're not the lowest bid, so let me address that directly: our last five public projects finished within 1.8% of contract value, and the gap between our bid and the lowest is less than the average change-order growth on projects of this type."},
    {"id":"narrative-constr-senior-04","level":"senior","profession":"construction","title":"The early-buy story","scenario":"You want the owner to release $380,000 for switchgear ten months early. Your draft explains procurement lead times. The persuasive version is a before/after: the project that waits discovers the delay in month twelve; the project that buys now never meets it.","task":"Write a 3-sentence case framed as two futures: the one where they buy now and the one where they don't.","tips":["Tell both futures concretely — same building, two endings.","Put a number on the bad future: three months of general conditions plus winter.","The ask lands as the bridge between the futures, not as a purchase order."],"focus":["impact","clarity"],"placeholder":"There are two versions of next winter: in one, the switchgear is in our warehouse by June and nobody ever thinks about it again; in the other, we're heating a finished building with rented generators for three months at $40K a month."},
    {"id":"narrative-constr-senior-05","level":"senior","profession":"construction","title":"The corner lot, told as a story","scenario":"You're speaking for your client's rezoning at council. The staff report is all metrics — density, setbacks, parking ratios. What moves council is the story of the lot: fifteen years vacant, a fence collecting garbage, and what stands there in three years if they vote yes.","task":"Speak the 3-sentence story: the lot as it is, the lot as it will be, and the bridge tonight's vote provides.","tips":["Open on the place everyone in the room has walked past.","Paint the after with people in it: forty households, ground-floor shops lit at night.","Make tonight's vote the hinge between the two pictures."],"focus":["audience","impact"]},
    {"id":"narrative-constr-senior-06","level":"senior","profession":"construction","title":"Prefab past the quality objection","scenario":"You want the developer to accept prefabricated bathroom pods — eight weeks off the schedule, real money saved. You know his objection before he says it: 'prefab means cheap.' If you don't raise and kill that objection, it kills the idea in his head while you're still talking.","task":"Write a 3-sentence pitch that names the quality objection first and answers it with evidence.","tips":["Say his objection out loud before he does — it's disarming and honest.","Answer with evidence he can touch: a factory tour, a finished unit, the tolerance specs.","Then land the prize: eight weeks and the trades bottleneck gone."],"focus":["impact","audience"],"placeholder":"You're going to hear 'prefab' and think cheap — so let me take you through a factory where the tolerances are tighter than anything we achieve on site. If the pod I show you isn't better than a site-built bathroom, we drop the idea in the parking lot."},
    {"id":"narrative-constr-senior-07","level":"senior","profession":"construction","title":"Safety told as a story","scenario":"Your monthly safety talk to the foremen is a recitation of stats, and you can watch it bounce off. This month you want to talk about tie-off compliance, and you have something better than a number: what happened on the Pearson job in 2019, which you were there for.","task":"Speak the 3-sentence version of the story and the one rule you want it to carry.","tips":["A specific person on a specific day beats any frequency rate.","Tell it plainly — drama is in the facts, not the delivery.","Land the rule as the story's conclusion, not a policy add-on."],"focus":["audience","impact"]},
    {"id":"narrative-constr-senior-08","level":"senior","profession":"construction","title":"The case for negotiating, not tendering","scenario":"Your repeat client is about to put her next building out to open tender, as her board expects. You want the negotiated contract. Her board's objection is obvious: 'competition gets us a better price.' Your answer has to beat that instinct with evidence, not charm.","task":"Write a 3-4 sentence case for negotiation that meets the competition objection head-on.","tips":["Concede what's true: tendering optimizes the day-one price.","Then reframe: final cost is the number that matters, and open tenders buy claims.","Offer the protection: open-book pricing, a benchmarked fee, audit rights."],"focus":["impact","precision"],"placeholder":"An open tender will beat my number on day one — I'll concede that now. What it won't beat is my final cost: negotiated jobs finish without the claims war that low-bid contracts are priced to start. Take it to your board with open-book pricing and full audit rights, and let the final numbers make the argument."},
    {"id":"narrative-constr-senior-09","level":"senior","profession":"construction","title":"From chronology to causation","scenario":"Your delay claim reads like a diary: forty dated entries, no argument. The reviewer needs a story with a spine: the owner's late steel decision set off a chain that ends at the six-week overrun, and every entry either builds that chain or belongs in an appendix.","task":"Write the 2-3 sentence causation summary that would open the claim.","tips":["Name the cause, the chain, and the effect in the first sentence.","Every link gets a date and a document reference.","A chronology proves you kept records; a causation story wins the claim."],"focus":["structure","precision"],"placeholder":"The owner's steel package decision, due March 1 and issued March 24, delayed fabrication by 23 days, pushed erection into the April weather window, and drove the six-week overrun this claim quantifies — each link documented in Sections 3 through 5."},
    {"id":"narrative-constr-senior-10","level":"senior","profession":"construction","title":"Persuading the lender to extend","scenario":"The construction loan matures in 60 days and the building needs 90 more. The bank's committee will read your request as a failing-project story unless you give them a different one: a de-risked project asking for a technical extension, not a rescue.","task":"Write the 3-sentence framing that opens your extension request letter.","tips":["Frame from completion backward: what's done, what's sold, what remains.","The overrun story is about the past; the extension story must be about the finish line.","Give the committee the sentence they can repeat: 'de-risked asset, 90 days from revenue.'"],"focus":["audience","impact"],"placeholder":"This is a request to carry a de-risked asset across its final 90 days: the building is 92% complete, 78% pre-leased, and every remaining trade is under contract with materials on site."},
    {"id":"narrative-constr-senior-11","level":"senior","profession":"construction","title":"The trades pitch at the school","scenario":"You have five minutes with a gym full of high-school students to make carpentry apprenticeship real against the pull of university-by-default. Statistics about labour shortages mean nothing to a seventeen-year-old. What means something: a person their age, a paycheque, and something they built standing there.","task":"Speak the 3-sentence opening, built on a concrete before/after a student can see themselves in.","tips":["Start with a person, not an industry: 'four years ago, Priya sat where you're sitting.'","Make the stakes theirs: earning at 19 versus owing at 23.","End with something built — a thing they can point at from a car window forever."],"focus":["audience","impact"]},
    {"id":"narrative-constr-senior-12","level":"senior","profession":"construction","title":"VE as a win, not a loss","scenario":"The budget requires switching the lobby from imported stone to large-format porcelain, saving $95,000. Presented as a cut, the owner mourns the stone forever. Presented as a trade with its own gains — lighter structure, faster install, easier replacement — it's a decision she can own proudly.","task":"Write the 2-3 sentence framing that presents the substitution as a trade, not a downgrade.","tips":["Never open with what's lost — open with what the change buys.","Name the gains that are real: weight, schedule, lifetime maintenance.","Close by putting the saved money somewhere she cares about."],"focus":["impact","audience"],"placeholder":"The porcelain buys you three things the stone couldn't: two weeks of schedule, a floor that doesn't crack at the slab joints, and $95K — which, put into the lobby lighting package, changes the room more than the stone ever would."},
    {"id":"narrative-constr-senior-13","level":"senior","profession":"construction","title":"Selling the phased move-in","scenario":"The anchor tenant wants the whole floor on June 1; the building can give them the east half June 1 and the west half July 15. Presented as a shortfall, it's a breach conversation. Presented as a plan built around their move — IT first, staff waves, zero business interruption — it's a service.","task":"Write the 3-sentence proposal that frames phasing as designed around their operation.","tips":["Lead with what they get on their date, not what they don't.","Show you've thought about their move: server room ready first, moving dock reserved.","The objection to kill: 'construction workers around our staff' — name the separation plan."],"focus":["structure","impact"],"placeholder":"On June 1 you get the east half — including your server room and reception, finished first by design — so your IT cutover and first staff wave land on schedule. The west half follows July 15, fully separated behind a sealed partition with its own construction entrance."},
    {"id":"narrative-constr-senior-14","level":"senior","profession":"construction","title":"The neighbours before the hearing","scenario":"Your variance hearing is in three weeks and the adjacent homeowners are organizing against it. Their real grievance, gathered from the community meeting: parking spillover. A letter that argues zoning law loses; a letter that solves their actual problem might turn opponents into neutrals.","task":"Write the 2-3 sentence core of the letter: their concern named fairly, your concrete commitment, the invitation.","tips":["State their objection more fairly than they state it — that's what earns the hearing.","Commit to something checkable: trade parking on site, a contact who answers.","Ask for the meeting, not the support; neutrality is the realistic win."],"focus":["audience","impact"]},
    {"id":"narrative-constr-senior-15","level":"senior","profession":"construction","title":"The acceleration pitch","scenario":"The project is five weeks behind and the owner can fund an acceleration package — $120,000 for overtime and a second crew — or ride it out. Your draft presents acceleration as an expense. The persuasive frame prices both options: the package against five weeks of carrying costs and lost rent.","task":"Write the 2-3 sentence case that prices doing nothing and makes the package the cheaper choice.","tips":["The cost of inaction is the argument — carrying costs, lost rent, the lease penalty.","Put both numbers side by side in one sentence.","Recommend; don't just present the arithmetic."],"focus":["impact","precision"],"placeholder":"Five weeks late costs you roughly $210K — $85K in carrying costs and $125K in lost rent and lease penalties. The acceleration package is $120K and buys back four of the five weeks, which is why I recommend it."},
    {"id":"narrative-constr-senior-16","level":"senior","profession":"construction","title":"The case for the next job","scenario":"Your client's warehouse finished well, and their sister company is planning a distribution centre. You want it negotiated, without a bid. Your case isn't charm — it's the measured record of the job just done, told so a CFO who wasn't on site believes it.","task":"Write the 3-sentence case built on verifiable performance, aimed at the sister company's CFO.","tips":["Numbers a CFO can check: final cost versus contract, dates promised versus hit.","One line on what carries over: the team, the subs, the lessons already paid for.","The ask is specific: a negotiated preconstruction agreement, not 'keep us in mind.'"],"focus":["precision","impact"],"placeholder":"The Brampton warehouse finished eleven days early and 0.9% under contract — numbers your colleagues at Westgate can verify in an afternoon. The same team, the same sub trades, and every lesson from that building are available to your distribution centre without the eight weeks and risk premium of a tender."},
    {"id":"narrative-constr-senior-17","level":"senior","profession":"construction","title":"Holding the fabricator's price","scenario":"Your steel fabricator wants to reopen his price — up 6% — citing material costs, on a job that starts in five weeks. You can fight the contract language, or you can persuade: he's bidding your next three projects, and this job is the audition his estimators should be pricing for.","task":"Write the 2-3 sentence appeal that gives him a business reason to hold, beyond the contract.","tips":["Acknowledge his squeeze — dismissing it hardens him.","Make the pipeline concrete: name the three projects and their tonnage.","Offer something real that isn't price: faster payment, the next negotiation's first call."],"focus":["impact","audience"],"placeholder":"I know the material market is real, and I'm not pretending it isn't. Here's what I can offer instead of reopening the price: fifteen-day payment on this job, and first look at the three projects behind it — about 2,400 tonnes over two years."},
    {"id":"narrative-constr-senior-18","level":"senior","profession":"construction","title":"The appeal to the adjuster","scenario":"The insurer denied $80,000 of your storm claim, calling the soaked drywall replacement 'betterment.' Your appeal letter needs a story the file reviewer can approve: the mitigation you did within hours, the code that forced the assembly change, and the documents that prove both.","task":"Write the 2-3 sentence appeal framing: the mitigation story, the code driver, the documented ask.","tips":["Lead with your diligence — same-day mitigation reframes you as the careful insured.","'Betterment' dies against a code citation: the old assembly can't legally go back.","Every claim in the letter points to an exhibit number."],"focus":["precision","structure"],"placeholder":"Within six hours of the loss we had extraction and drying underway, which the logs at Exhibit C document — this claim comes from a careful insured. The disputed $80,000 is not betterment: OBC 9.10 no longer permits the original assembly, so the code-required replacement is the only lawful repair."},
    {"id":"narrative-constr-senior-19","level":"senior","profession":"construction","title":"Convincing your own partner","scenario":"You want the firm to spend $150,000 on project-management software and a coordinator to run it. Your partner has heard 'this will change everything' before. What he hasn't heard is the before/after in the firm's own numbers: the hours, the write-offs, the claim you nearly lost for want of documentation.","task":"Write the 3-sentence internal pitch built on the firm's own before/after numbers.","tips":["Use your own data, not the vendor's — he'll trust the write-off ledger.","Name the near-miss: the claim that almost failed on missing daily records.","Frame the spend against one number it protects."],"focus":["impact","precision"],"placeholder":"Last year we wrote off $220K in unbilled changes because the paper trail wasn't there, and the Meridian claim nearly died for want of daily records. This is $150K to make both impossible."},
    {"id":"narrative-constr-senior-20","level":"senior","profession":"construction","title":"The award entry with a spine","scenario":"You're writing the industry-award submission for the heritage theatre restoration. Your draft is a feature list: scope, budget, techniques. Award juries read forty of those. The winning entries tell a change story: what was at stake, what stood in the way, what exists now because of how it was built.","task":"Write the 3-sentence opening of the submission as a story, not a specification.","tips":["Open with the stakes: a century-old theatre three years from demolition.","The obstacle is the drama — the unmapped structure, the occupied block, the immovable opening date.","End on the after, with people in it."],"focus":["structure","impact"]},
    {"id":"narrative-constr-senior-21","level":"senior","profession":"construction","title":"The fee proposal's hardest sentence","scenario":"Your construction-management fee proposal will hit the client's desk beside two lower ones. Rather than hope they don't notice, the proposal should say why the number is higher — in one confident paragraph that reframes the comparison before procurement makes it on a spreadsheet.","task":"Write the 2-3 sentences that address the fee gap head-on inside the proposal.","tips":["Raise the comparison yourself; a spreadsheet will otherwise make it for you.","Attach the fee to named risk you carry that the others exclude.","One verifiable proof point: your change-order history or final-cost record."],"focus":["impact","audience"],"placeholder":"Our fee will read higher than others on your shortlist, and the difference is what it includes: full-time site supervision rather than shared, and a preconstruction estimate we stand behind contractually. Our last eight CM projects finished within 2% of that estimate — ask the others for the same table."},
    {"id":"narrative-constr-senior-22","level":"senior","profession":"construction","title":"The schedule the trades believe in","scenario":"At the kickoff meeting, twelve sub trades will hear the milestone schedule. Read as your schedule, it's wallpaper; sold as theirs, it holds. The persuasive move is to make the critical handoffs — and what each trade gains from the ones before it holding — vivid enough to create peer pressure.","task":"Speak the 2-3 sentences that frame the schedule as a chain of promises between trades.","tips":["Name a real handoff: drywall's start date is the framer's promise kept.","Make the mutual stake explicit — every trade in the room is downstream of someone.","Invite the objection now: 'if your date is wrong, say it today, not in August.'"],"focus":["audience","impact"]},
    {"id":"narrative-constr-senior-23","level":"senior","profession":"construction","title":"Talking the owner out of early move-in","scenario":"The owner wants to move furniture in two weeks before substantial completion — 'the building's basically done.' It voids nothing on paper he can see, and everything in practice: insurance, occupancy permit, trade productivity. A lecture loses; a concrete picture of the bad afternoon might not.","task":"Write the 2-3 sentence persuasion built on one vivid, specific consequence.","tips":["Pick the single sharpest consequence — the insurer walking away from a loss — and make it concrete.","Give the stakes a scene: his furniture, a sprinkler test, no coverage.","Offer the compromise that meets his real need: early access to one finished, permitted zone."],"focus":["impact","clarity"],"placeholder":"Picture one bad afternoon: your furniture is in, a sprinkler line lets go during commissioning, and the insurer denies the claim because the building had no occupancy permit — that's the actual risk, and it's yours not mine. Give me the two weeks, and I'll hand you the east wing early, permitted and insured, to start staging."},
    {"id":"narrative-constr-senior-24","level":"senior","profession":"construction","title":"Reopening the shelved project","scenario":"A developer shelved his mixed-use project eighteen months ago when construction pricing peaked. Prices have come off 8-10% and two of his competitors just broke ground. A 'checking in' email gets deleted; a letter that reframes the moment — the cost window and the competitive clock — gets a meeting.","task":"Write the 3-sentence letter opening that makes the case for reopening now.","tips":["Lead with the changed fact: pricing is off its peak, with numbers.","Add the clock: competitors under way, the leasing window.","The ask is small and specific: a one-hour repricing session, free."],"focus":["impact","structure"],"placeholder":"The market that shelved your project has moved: structure and envelope pricing is down 8-10% from when we last budgeted, which on your building is roughly $2.1M. Meanwhile two comparable projects broke ground within a kilometre this spring, and they'll reach the leasing market first."},
    {"id":"narrative-constr-senior-25","level":"senior","profession":"construction","title":"Thirty pages to one paragraph","scenario":"Your lifecycle cost analysis proves the school board should spend $400,000 more on the better mechanical system — thirty pages of net-present-value tables prove it. The board will read one paragraph, and trustees vote on stakes they can retell to a taxpayer.","task":"Write the one-paragraph (3-sentence) version: the choice, the stakes in taxpayer terms, the recommendation.","tips":["Compress the whole analysis into one comparison a trustee can repeat.","Translate NPV into their units: dollars per year, over the life their voters will own it.","End with the recommendation, owned."],"focus":["concision","impact"],"placeholder":"The board's choice is $400,000 now or roughly $180,000 every year in extra energy and maintenance for the thirty years this school will stand. The better system pays for itself before the first students graduate. I recommend the board approve it."}
  ],
  "delivering-hard-messages": [
    {"id":"hard-constr-senior-01","level":"senior","profession":"construction","title":"Telling the owner the budget is gone","scenario":"The forecast now shows the project finishing $310,000 over the GMP, and no soft framing changes the number. Your draft email spends two paragraphs on context before the figure appears. The owner will feel the delay in the telling as deception, not tact.","task":"Write the 2-3 sentence opening that states the overrun first, plainly, with the drivers and the meeting ask.","tips":["The number goes in sentence one — burying it converts a cost problem into a trust problem.","Name the two or three drivers in a single sentence.","Close the opening with the working session where options get decided."],"focus":["clarity","impact"],"placeholder":"The forecast now shows us finishing $310,000 over the GMP, driven by the rock condition, the steel escalation, and the mechanical rework. I want an hour Thursday to walk you through the options I've priced for closing part of that gap."},
    {"id":"hard-constr-senior-02","level":"senior","profession":"construction","title":"Terminating the drywall sub","scenario":"After two cure notices and a third week of no crew, you're terminating the drywall sub's contract. You've known the owner fifteen years, and he'll ask for one more chance on the call. The message must be final without being cruel — hedging now just schedules a worse call next week.","task":"Write the 2-3 sentence core of the termination call: the decision as final, the reason, the mechanics.","tips":["State the termination as decided, not as a threat still open to negotiation.","The reason is the record: two cure notices, dates, no crew.","Respect the fifteen years in tone; protect the project in substance."],"focus":["clarity","impact"],"placeholder":"Tom, I'm terminating the contract effective today — this call is to tell you, not to negotiate it. Two cure notices went unanswered and the job has had no crew for three weeks; I've run out of road."},
    {"id":"hard-constr-senior-03","level":"senior","profession":"construction","title":"Behavior, impact, ask for the super","scenario":"Your best superintendent runs an excellent site, but his daily reports arrive late and half-empty — and the delay claim you're building leans on exactly those records. He'll hear vague criticism as an insult to good work. He needs the specific behavior, its real impact, and a clear ask.","task":"Write the 3-sentence feedback: the behavior factually, the impact concretely, the ask specifically.","tips":["Name the behavior without character judgment: reports late and missing manpower counts.","The impact is real money: the claim rests on those records.","One doable ask with a standard: complete, same-day, every day."],"focus":["clarity","structure"],"placeholder":"Your dailies are landing two or three days late with the manpower and weather sections empty. The delay claim we're carrying rests on exactly those records — every blank field is money we can't prove. I need them complete and submitted same-day, starting Monday."},
    {"id":"hard-constr-senior-04","level":"senior","profession":"construction","title":"The client's brother-in-law's bid","scenario":"Your client wants his brother-in-law's small electrical firm on the project. You checked: no comparable project experience, no capacity for this size, and your license and schedule carry the risk. A vague deferral will drift back as pressure. The no has to be clean and survivable.","task":"Write the 2-3 sentence no: clear, reasoned, and with the door open for something honest.","tips":["Say no to the placement plainly — 'I have concerns' reads as negotiable.","The reason is scale and risk, not the man's character.","Offer what's true: a scope his size, or first call on the next small job."],"focus":["clarity","audience"],"placeholder":"I can't award him the electrical package — this is a $1.2M scope with a crew of twelve, and his firm has never carried more than three. What I can do honestly is the standalone garage package, which is right-sized for him and lets him prove out for the next job."},
    {"id":"hard-constr-senior-05","level":"senior","profession":"construction","title":"The winter layoff talk","scenario":"Work is thin until March and you're laying off two carpenters this Friday — good hands, no fault of theirs. You'll tell them face to face. The instinct is to bury the news under praise and maybes; what they need is the fact, the date, the honest outlook, and what you'll do for them.","task":"Speak the opening 2-3 sentences: the layoff stated first, the reason honestly, the support named.","tips":["Say it in the first sentence — they'll know why they're in the trailer anyway.","No false hope about recall dates you can't stand behind.","Name the concrete help: the reference call, the two contractors who are hiring."],"focus":["clarity","audience"]},
    {"id":"hard-constr-senior-06","level":"senior","profession":"construction","title":"No to the free extras","scenario":"The homeowner keeps asking for 'little things while you're here' — a floating shelf, an extra hose bib, moving a switch. Each is small; together they're $4,000 of unpaid work, and your crew has started rolling their eyes. The relationship is good, which is exactly what mumbling yeses is spending down.","task":"Write the 2-3 sentence message that stops the free work cleanly while keeping the warmth.","tips":["Name the pattern kindly but plainly — the accumulating asks, not any single one.","The mechanism is the kindness: everything gets a written quote, however small.","A clean rule survives the relationship; resentment doesn't."],"focus":["clarity","impact"],"placeholder":"I want to flag something before it gets awkward: the small add-ons have quietly become about $4,000 of work outside our contract. From here, anything new gets a quick written quote first — most will be small, but that keeps us square and keeps my crew whole."},
    {"id":"hard-constr-senior-07","level":"senior","profession":"construction","title":"The design is over budget","scenario":"The developer's architect is at 90% drawings and your live pricing says the design is $1.8M over the stated budget. Everyone at the table half-knows; nobody has said the number. Saying it now costs a hard meeting — saying it at tender costs the developer six months of redesign.","task":"Write the 2-3 sentence message to the developer that states the gap now, plainly, with the path.","tips":["State the number and the confidence level in sentence one.","Do not soften it into 'some budget pressure' — the redesign decision needs the true size.","Offer the path: a VE workshop now, while changes are still cheap on paper."],"focus":["clarity","impact"],"placeholder":"Priced at 90% drawings, the design is $1.8M over your budget, and my confidence in that number is high. I'd rather give you this now, while it's a drawing problem, than at tender when it's a six-month problem — I've booked my estimator for a VE workshop whenever your architect can sit down."},
    {"id":"hard-constr-senior-08","level":"senior","profession":"construction","title":"The warranty claim that isn't","scenario":"The homeowner's basement leak traces to the window well her landscaper buried when regrading last summer — not your waterproofing. She's anxious and expects you to cover it. The denial must be clear, the evidence offered, and the relationship — and your referral pipeline — kept intact.","task":"Write the 2-3 sentence response: the finding stated plainly, the evidence offered, and a constructive next step.","tips":["Lead with the finding, not the contract clause.","Offer the evidence: photos, the original grading survey — proof beats assertion.","Give her a path: what the fix is and a fair price to do it."],"focus":["clarity","audience"],"placeholder":"We found the source, and it isn't the waterproofing: the regrading last summer buried the window well and directs water straight at it — I'll send you the photos beside the original grading survey so you can see it yourself. It's not a warranty item, but it's a half-day fix, and I'll quote it fairly if you want us to handle it."},
    {"id":"hard-constr-senior-09","level":"senior","profession":"construction","title":"Correcting last month's report","scenario":"Last month you told the lender the project was on schedule. It was — but the elevator inspection backlog has since moved substantial completion three weeks, and this month's report must say so. The temptation is continuity language that blurs the change. Banks forgive slips; they don't forgive discovering them late.","task":"Write the 2-3 sentence correction that names the change from last month's report explicitly.","tips":["Reference your own last report — 'this is a change from what I told you' is the trust-preserving move.","Give the new date, the single driver, and the containment.","Blurring the change is the only unforgivable version."],"focus":["clarity","impact"],"placeholder":"This month's report contains a change from my last one: substantial completion has moved three weeks, to April 22, driven entirely by the municipal elevator-inspection backlog. Draw schedule impact is one period, and the interest reserve covers it."},
    {"id":"hard-constr-senior-10","level":"senior","profession":"construction","title":"Firing the long-time foreman","scenario":"Your concrete foreman of eleven years falsified a fall-protection inspection record — the second documented safety integrity issue this year. You're letting him go today, in person. Eleven years deserves directness and dignity; it doesn't change the decision, and the conversation can't suggest it might.","task":"Speak the opening 2-3 sentences: the decision first, the reason specifically, the dignity intact.","tips":["The decision comes first — a wind-up makes him negotiate against hope.","Name the specific cause; vagueness invites argument and rumor.","Dignity is in the logistics: the private room, the fair severance, the honest handshake."],"focus":["clarity","audience"]},
    {"id":"hard-constr-senior-11","level":"senior","profession":"construction","title":"Declining the repeat client's project","scenario":"Your best repeat client asked you to build his family's cottage — three hours north, a market you don't know, at a size below your overhead structure. Every version of yes ends with him overpaying or you underdelivering. Saying no to good work from a good client is the hard message.","task":"Write the 2-3 sentence decline that protects both the client and the relationship.","tips":["Decline in the first sentence — a slow no reads as a shakedown for margin.","The reason is his interest: your rates and distance make you the wrong buy.","Give the referral: the two builders up there you'd trust with your own cottage."],"focus":["clarity","audience"],"placeholder":"I'm going to say no to this one, and here's why it's the right answer for you: at three hours' distance my supervision costs make me 20% more expensive than a good local, with no better result. Call Hendricks or North Bay Timberworks — I'd let either build my own place, and I'll walk your drawings with whichever you pick."},
    {"id":"hard-constr-senior-12","level":"senior","profession":"construction","title":"The architect's detail won't build","scenario":"The architect's signature stair detail — a glass guard with a concealed fixing — can't be built as drawn: the fixing has no engineering path and two fabricators have refused it. She's proud of it and the owner loves the renderings. The message must be direct without being a shot at her competence.","task":"Write the 2-3 sentence message: the buildability problem stated plainly, evidence attached, and a working session proposed.","tips":["State the problem as fact with the fabricators' letters attached — not as opinion.","Separate the design intent (achievable) from the detail (not) — that's the face-saving line.","Propose the fix session before she has to ask for it."],"focus":["clarity","precision"],"placeholder":"The stair guard detail at A-501 can't be built as drawn — the concealed fixing has no load path, and both fabricators we approached have declined it in writing (attached). The design intent is absolutely achievable with a modified base channel, and I'd like an hour with you and the fabricator this week to get there before it touches the schedule."},
    {"id":"hard-constr-senior-13","level":"senior","profession":"construction","title":"The wrong stone at the walkthrough","scenario":"The custom fireplace stone arrived and it's wrong — the supplier cut from a different lot, and the replacement is eight weeks out. The owners walk the house tomorrow and will see it immediately. You call tonight. The news must come from you, complete, before they discover it themselves.","task":"Write the 2-3 sentence call opening: the problem, the timeline, and what you've already done.","tips":["Call before the walkthrough — discovered bad news is twice as bad.","Give the full size of it at once: wrong lot, eight weeks, and the interim plan.","Have the remedy already moving: reorder placed, supplier covering costs."],"focus":["clarity","impact"],"placeholder":"I want you to hear this from me before tomorrow's walkthrough: the fireplace stone arrived from the wrong lot and it's visibly off from your sample — I've rejected it, and the correct stone is eight weeks out. The reorder is already placed at the supplier's cost, and everything else stays on schedule for your move-in."},
    {"id":"hard-constr-senior-14","level":"senior","profession":"construction","title":"The rate increase letter","scenario":"Costs have moved and your rates are going up 8% for the new year — including for three loyal clients with projects in early planning. The letter must state the increase plainly and early, without a page of apology for running a business, and honour any numbers you've already committed.","task":"Write the 2-3 sentence core of the letter: the increase, the effective date, and what's protected.","tips":["State the number and date in the first sentence — apology-first letters read as negotiable.","One honest sentence of driver: labour and insurance, up materially.","Protect what's promised: signed proposals hold their pricing."],"focus":["clarity","audience"],"placeholder":"Effective March 1, our rates increase by 8% — the first adjustment in three years, driven by labour and insurance costs that have moved well past that. Any proposal we've already signed holds its current pricing, and estimates in progress will be honoured through February."},
    {"id":"hard-constr-senior-15","level":"senior","profession":"construction","title":"Refusing the impossible date","scenario":"The developer needs the retail podium open by November for the holiday season and wants you to commit. The honest build is fourteen months; his date requires eleven. Signing up to it books a certain failure with your name on it. The no must be firm, and it must come with what yes would take.","task":"Write the 2-3 sentence refusal that declines the date and states what would have to change to hit it.","tips":["Decline the date itself, not vaguely: 'I won't commit to November.'","Show the arithmetic in one sentence — where the three months actually live.","Offer the real options: a phased retail opening, or the scope that makes November true."],"focus":["clarity","impact"],"placeholder":"I won't sign up for November — the honest schedule is fourteen months, and the three-month gap lives in structure and envelope, which no amount of overtime compresses safely. What I can commit to: the ground-floor retail shell open for November with the tower finishing in February, if we resequence now."},
    {"id":"hard-constr-senior-16","level":"senior","profession":"construction","title":"Reporting your own defect","scenario":"Your quality walk found a section of below-grade waterproofing your crew lapped wrong before backfill — nobody else has seen it, and the fix means excavating thirty feet of foundation at your cost. Telling the owner is expensive; the owner finding out later is fatal.","task":"Write the 2-3 sentence self-report: the defect, the fix underway at your cost, and the verification offered.","tips":["Volunteer it completely — half-disclosures discovered later read as cover-ups.","Lead with the fix already scheduled, at your cost, before they ask.","Offer verification: their consultant inspects the redone work."],"focus":["clarity","impact"],"placeholder":"My own quality walk caught a defect I want you to know about today: about thirty feet of foundation waterproofing was lapped wrong before backfill. We're excavating and redoing it next week at our cost, and I'd like your envelope consultant to inspect it before we backfill again."},
    {"id":"hard-constr-senior-17","level":"senior","profession":"construction","title":"The sub who bid too low","scenario":"The masonry bid you received is 30% under the next two — the sub missed the scaffolding scope, you're almost certain. Taking the number is legal and will bankrupt him by month four, wrecking your schedule with him. The hard, kind message: your bid has a hole, check it before I can use it.","task":"Write the 2-3 sentence call: the concern named specifically, without doing his estimating for him.","tips":["Point at the gap — 'walk your scaffolding scope again' — without dictating his price.","Kindness with a deadline: he has until Thursday to confirm or correct.","A sub who fails mid-job costs you more than the bid difference ever saved."],"focus":["audience","clarity"],"placeholder":"Before I can use your number, I need you to walk it again — you're 30% under the field, and the gap smells like scaffolding scope to me. Take until Thursday: if the number's real after that, I'll take it, and if it isn't, fix it now rather than in month four."},
    {"id":"hard-constr-senior-18","level":"senior","profession":"construction","title":"Ending the joint venture","scenario":"The JV that was supposed to split management of the transit-station job has become you managing and them invoicing. With the next phase's agreement unsigned, this is the moment to end it. He's a friend of twenty years, which is why the message has to be clear rather than slow.","task":"Write the 2-3 sentence message: the decision, the honest reason, and the clean unwind proposed.","tips":["Decision first — twenty years of friendship deserves a straight answer, not a fade.","The reason is the pattern, stated once, without a litigated history.","Propose the mechanics: current phase honoured, next phase solo, the accounting clean."],"focus":["clarity","impact"],"placeholder":"I'm not signing the phase-two JV — I want to say that plainly and to you first. The split we agreed hasn't been the split we've lived: my team has carried the management load for eighteen months. Let's finish phase one exactly as agreed, unwind the books clean, and protect the friendship by not pretending otherwise."},
    {"id":"hard-constr-senior-19","level":"senior","profession":"construction","title":"Moving the PM back down","scenario":"You promoted your best coordinator to PM eight months ago and it isn't working: two blown client meetings, a missed notice deadline, a team routing around him. You're moving him back to senior coordinator — a demotion, whatever it's titled. He's talented, loyal, and about to hear the hardest message of his career.","task":"Speak the opening 2-3 sentences: the decision plainly, the specific reasons, and what remains true about his value.","tips":["Say the decision in the first breath — hope-management mid-conversation is cruelty.","Two specific reasons, not a performance-review fog.","What's true stays true: his coordination work is the best in the firm, and the door isn't closed forever."],"focus":["clarity","audience"]},
    {"id":"hard-constr-senior-20","level":"senior","profession":"construction","title":"The stop-work you ordered","scenario":"You shut down the excavation this morning — the shoring didn't match the engineer's drawing, full stop. The owner loses a day and the excavation sub loses face, and both are calling. The message to each: the decision was correct, here's the standard, here's when work resumes.","task":"Write the 2-3 sentence message to the owner: the stop, the reason, the resumption condition — with zero apology for the safety call.","tips":["State the stop as the system working, not as a failure to explain away.","The standard is the drawing — objective, checkable, no judgment call to argue.","Resumption is conditional, not scheduled: when the shoring matches, work resumes."],"focus":["clarity","impact"],"placeholder":"I stopped the excavation this morning: the installed shoring didn't match the engineer's drawing, and that's not a risk anyone on my site runs. The sub is correcting it under the engineer's review today, and work resumes the moment it's verified — likely tomorrow morning."},
    {"id":"hard-constr-senior-21","level":"senior","profession":"construction","title":"The upgrade list meets the allowance","scenario":"The buyers' selections are $38,000 over their allowances, and they're still adding. Every 'we'll sort it out later' from you has let it grow. The message: here's the running total, the contract math, and the decision point — before the orders go in, not at the final invoice.","task":"Write the 2-3 sentence message that states the overage now and forces the decision honestly.","tips":["Give the running total in sentence one — the kindness is in the timing.","Restate the mechanism they agreed to: over allowance means the difference is theirs.","Offer the review session before any order is placed."],"focus":["clarity","audience"],"placeholder":"Before we place the next orders, you need the running total: your selections are now $38,000 over the allowances in the contract, and that difference is billed to you at closing. Let's sit down Thursday with the full list — there are three places we can claw back most of it if you want to."},
    {"id":"hard-constr-senior-22","level":"senior","profession":"construction","title":"The last call before the lien","scenario":"Ninety days unpaid, three friendly reminders ignored, and the lien deadline is eleven days out. This client is a referral source and a genuine friend of the firm — and the next message is a lien if this one fails. It must say so plainly, without either groveling or menace.","task":"Write the 2-3 sentence message: the amount, the deadline-driven step, and the off-ramp.","tips":["Frame the lien as a statutory deadline you don't control, because it is.","Give the exact off-ramp: payment or a signed schedule by a named date.","Neither apologize for collecting nor threaten — describe what happens and when."],"focus":["clarity","impact"],"placeholder":"The $148,000 is now 90 days past due, and I have to be straight with you about what happens next: to preserve our lien rights we must file by the 21st, and I don't get to extend that date. Payment — or a signed payment schedule — by the 18th takes it off the table entirely, and that's the outcome I want."},
    {"id":"hard-constr-senior-23","level":"senior","profession":"construction","title":"Telling the owner they're the delay","scenario":"The project is four weeks behind, and the honest cause is the owner: three decision packages sat with them past deadline. They're frustrated with you. The message must put the cause on the record without turning the relationship adversarial — facts and dates, not blame adjectives.","task":"Write the 2-3 sentence message that names the owner-caused delay factually and redirects to the fix.","tips":["Dates and documents, no blame words: 'the flooring package, due March 1, was returned March 26.'","Pair every fact with the forward fix: a decision calendar with named owners.","The tone test: could they read it aloud to their board without flinching?"],"focus":["audience","impact"],"placeholder":"The four-week slip traces to three decision packages — flooring, hardware, and the lobby ceiling — which were returned 25, 18, and 11 days past their scheduled dates. No one needs to relitigate why; what I need is the attached decision calendar agreed this week, so the remaining forty decisions land on time."},
    {"id":"hard-constr-senior-24","level":"senior","profession":"construction","title":"Passing through the insurer's denial","scenario":"The insurer denied the condo board's water-damage claim — pre-existing deficiency, they say — and you're the one presenting the denial at tonight's board meeting. It isn't your denial, but you'll be standing next to it. The message: the decision, what it means, and the two real paths from here.","task":"Write the 2-3 sentence opening for the board: the denial stated plainly, the reason, and the options framed.","tips":["Deliver the denial in the first sentence; a wind-up makes a bad meeting worse.","Report the insurer's reason accurately without adopting or attacking it.","End on agency: the appeal path and the repair path, each with a number and a date."],"focus":["clarity","audience"],"placeholder":"The insurer has denied the claim — their position is that the membrane failure predates the policy — and I want to walk you through exactly what that means and the two paths forward. Tonight you have a real decision: fund the appeal with an independent engineer's report, or proceed directly to the $240,000 repair."},
    {"id":"hard-constr-senior-25","level":"senior","profession":"construction","title":"Withdrawing the bid","scenario":"Two days after tender close, your estimator found the error: a transposed line that makes your winning bid $600,000 too low. Performing at that number could sink the company; withdrawing costs your deposit and your face with an owner you courted for years. The call has to happen today.","task":"Write the 2-3 sentence call opening: the error owned completely, the withdrawal, and what you'll do to help.","tips":["Own the error without a single deflecting clause — it's yours.","State the withdrawal as decided; a builder who'd perform at a fatal number is not more trustworthy.","Offer what helps them: immediate release so they can move to the next bidder, and your pricing detail if useful."],"focus":["clarity","precision"],"placeholder":"I'm calling with hard news that's entirely our error: we found a transposition in our tender that makes our bid $600,000 below real cost, and I have to withdraw it. You'll have our formal withdrawal within the hour so you can move to the next bidder without losing a day — and I'll take the consequences under the tender rules on the chin."}
  ],
  "putting-it-together": [
    {"id":"together-constr-senior-01","level":"senior","profession":"construction","title":"The owner report, full stack","scenario":"Your monthly report to the developer has grown to nine pages nobody reads. This month carries real news: schedule holding, cost trending $95K over, and one decision needed on the facade mock-up. The covering paragraph has to do everything — headline, structure, precision, ownership — in four sentences.","task":"Write the 4-sentence covering paragraph: headline first, three labeled beats, one owned recommendation.","tips":["Sentence one carries the whole month: schedule, cost, the one decision.","Then one sentence each — schedule, cost, decision — in that announced order.","End owning your recommendation on the facade, not presenting a menu."],"focus":["structure","clarity"],"placeholder":"Three things this month: schedule is holding at May 15, cost is trending $95K over with a containment plan attached, and I need your facade mock-up decision by the 10th."},
    {"id":"together-constr-senior-02","level":"senior","profession":"construction","title":"The 90-second interview close","scenario":"The selection panel chair says: 'Ninety seconds — why your firm?' Everything you've trained collapses into this: the point first, a structure they can hear, no wasted words, calibrated confidence, and a close that lands the ask. Your competitors will ramble; the winner won't.","task":"Speak the 90-second close: your case in three signposted beats and a confident final sentence.","tips":["Open with the single sentence you'd want repeated in deliberations.","Three beats, announced: the team, the schedule record, the price integrity.","Land it: 'give us the job and here is the first thing we do Monday.'"],"focus":["impact","concision"]},
    {"id":"together-constr-senior-03","level":"senior","profession":"construction","title":"The claim cover letter that does it all","scenario":"Your $480,000 delay claim is documented across two binders. The cover letter is what the owner's executive actually reads, and it must be all the skills at once: the ask up front, the causation story in miniature, precise numbers, a steady register that invites settlement rather than war.","task":"Write the 3-4 sentence cover letter: the claim and amount, the one-sentence causation chain, the resolution path proposed.","tips":["Sentence one: what this is and the number — no wind-up.","One sentence of causation with dates; the binders carry the rest.","Close on the door you want them to walk through: a settlement meeting before formal steps."],"focus":["precision","structure"],"placeholder":"Enclosed is our delay claim for $480,000 under GC 8.3, arising from the owner-directed steel redesign of March 14 and the 31 working days it added to the critical path. The claim is documented event by event in the enclosed record. Before either of us spends money on formal proceedings, I'd like a settlement meeting in the next three weeks."},
    {"id":"together-constr-senior-04","level":"senior","profession":"construction","title":"Resetting the runaway thread","scenario":"The flooded-mechanical-room email thread is 47 messages deep: owner, architect, insurer, two subs, all replying at cross purposes. Someone has to reset it with one message that states where things stand, who owns what, and what happens next. That someone is you.","task":"Write the 3-4 sentence reset message: status headline, the three owned workstreams, the next checkpoint.","tips":["Change the subject line and open with the one-sentence status.","Structure by ownership: drying (yours), claim (insurer's), redesign (architect's) — one line each with a date.","End the thread: name the single update that replaces the reply-all storm."],"focus":["structure","clarity"],"placeholder":"Resetting this thread with where things stand: the room is dry, equipment is assessed, and there are three workstreams with three owners. Drying and reinstatement — us, complete by the 14th. Claim documentation — Hargrove Insurance, adjuster on site Tuesday. Replacement AHU spec — DKA Architects, sealed drawings by the 18th. I'll send one consolidated update every Friday; please direct replies to me only."},
    {"id":"together-constr-senior-05","level":"senior","profession":"construction","title":"The voicemail and its echo","scenario":"You need the fire-alarm verification rescheduled to Thursday or occupancy slips a week. The AHJ coordinator screens calls, so you'll leave a voicemail and send a two-line follow-up email — the pair has to work together: same headline, zero redundancy, everything he needs to say yes in either channel.","task":"Write both: the 3-sentence voicemail script and the 2-sentence email that lands behind it.","tips":["Voicemail: name, project, the ask with the date, callback number twice.","Email: same headline sentence, then the one logistical detail that makes yes easy.","Two channels, one message — never make him reconcile differences."],"focus":["concision","clarity"],"placeholder":"Voicemail: This is Dana Reyes, GC at 400 Harbourfront, 416-555-0140 — requesting the fire-alarm verification move to Thursday the 12th; the system is complete and the technician is on site all day. Email: Following my voicemail — requesting Thursday the 12th for the verification at 400 Harbourfront."},
    {"id":"together-constr-senior-06","level":"senior","profession":"construction","title":"One incident, three audiences","scenario":"A subcontractor's worker cut a live conduit this morning — no injury, power out for four hours, occupancy inspection at risk. Three messages leave your desk within the hour: the owner, your crew, and the insurer. Same facts, three registers, and each reader needs a different first sentence.","task":"Write the first sentence of each message: owner, crew, insurer — calibrated to what each needs first.","tips":["Owner: impact and containment — occupancy risk and your recovery move.","Crew: the safety lesson while the paint is wet — what changes today.","Insurer: date, event, cause as known, no speculation, notice preserved."],"focus":["audience","concision"],"placeholder":"Owner: This morning's conduit strike cost us four hours of power and does not threaten Thursday's inspection — here's why. Crew: Nobody got hurt today, and that was luck, not process — locates get verified before any cutting, starting now. Insurer: This letter provides notice of a property incident on June 12 at 400 Harbourfront — a subcontractor severed an energized conduit; no injury; damage assessment attached."},
    {"id":"together-constr-senior-07","level":"senior","profession":"construction","title":"The CO package that survives forwarding","scenario":"Your $210,000 mechanical change order will be forwarded by the owner's rep to a board that has never met you. The cover note must survive the journey alone: point first, cause precise, options honest, recommendation owned — because in that boardroom, the note is you.","task":"Write the 3-4 sentence cover note written for the furthest reader, not the nearest.","tips":["Assume no context: name the project, the change, the number in sentence one.","One sentence of cause with the document reference that proves it.","Give the board the decision shape: approve, reduce scope, or defer — and your pick."],"focus":["audience","precision"],"placeholder":"CO-021 requests $210,000 for the mechanical redesign required after the base-building ductwork was found 400mm below its drawn elevation (survey attached, ref S-11). The board has three options: approve in full, approve the reduced-scope version at $160,000 with two zones losing independent control, or defer — which stops mechanical rough-in on the 9th. I recommend full approval; the reduced scope saves $50,000 now and costs the tenants comfort for thirty years."},
    {"id":"together-constr-senior-08","level":"senior","profession":"construction","title":"Run the checklist on your own draft","scenario":"Your draft email to the lender runs 340 words: the point in paragraph three, two ideas braided together, hedges everywhere. Before sending, run the full checklist — point first? one governing idea? a third cut? specifics not vague claims? a position taken? — and rebuild it.","task":"Write the rebuilt 3-sentence version of a lender update whose news is: draw 6 requested, project 71% complete, one flag on elevator inspection timing.","tips":["First sentence: the ask (draw 6) and the number.","Second: the one status fact that supports it.","Third: the flag, owned, with your containment — not buried, not inflated."],"focus":["concision","clarity"],"placeholder":"Draw request 6, for $842,000, is attached with the consultant's certificate. The project is 71% complete against a 69% plan. One flag: the municipal elevator-inspection backlog could touch the final month — I've booked the earliest slot and will confirm impact, if any, by the 20th."},
    {"id":"together-constr-senior-09","level":"senior","profession":"construction","title":"The kickoff minute","scenario":"New project, first site meeting: the owner's team, your crew, and nine sub trades in one trailer. You get sixty seconds before the agenda to set how this job will run. Everything speaks at once here — structure, presence, audience, and the discipline to stop at sixty seconds.","task":"Speak the 60-second opening: what this job is, the three rules that make it run, and the tone you're setting.","tips":["One sentence on what's being built and why the date matters.","Three rules, numbered out loud — schedule promises, paperwork, safety authority.","Presence is brevity: end early and hand off to the agenda."],"focus":["structure","impact"]},
    {"id":"together-constr-senior-10","level":"senior","profession":"construction","title":"The final account letter","scenario":"Time to close out the two-year office project: final account of $6.44M, three disputed items worth $61,000, and a client you want for the next building. One letter must do it all — the reconciliation stated precisely, the disputes framed for resolution not war, the relationship banked.","task":"Write the 3-4 sentence letter: the final figure and its chain, the disputed items named with a proposed mechanism, the forward-looking close.","tips":["The chain in one sentence: contract + COs − paid = due.","Name the three disputes and propose the mechanism: one meeting, then the contract's process.","Close on the next building, briefly and without fawning."],"focus":["precision","impact"],"placeholder":"Our final account stands at $6,440,000 — the original $5.9M contract plus $540,000 in 22 approved change orders — leaving $186,000 due, of which $61,000 sits in three disputed items listed at Schedule A. I propose we resolve all three in a single meeting before month-end rather than through the formal process. It has been a good two years, and we'd like the next one."},
    {"id":"together-constr-senior-11","level":"senior","profession":"construction","title":"Two minutes at the podium","scenario":"The variance hearing is tonight and you have the standard two minutes at the public microphone. In the gallery: opposed neighbours, the press, your client. Every skill compresses into 240 words — audience-first framing, one clear structure, concrete commitments, and a close council can vote on.","task":"Speak the 2-minute statement: the community frame, the two commitments that answer the objections, the specific ask.","tips":["Open in the residents' interest, not the project's.","Two commitments maximum — checkable ones with numbers and hours.","End on the precise motion you're asking council to pass."],"focus":["audience","impact"]},
    {"id":"together-constr-senior-12","level":"senior","profession":"construction","title":"The apology that holds the line","scenario":"Saturday's concrete pour started at 7:01 a.m. and the neighbourhood association's complaint is on the councillor's desk by Monday. The pour was legal, permitted, and necessary — and the relationship with the street matters for two more years. Apologize for the impact; hold the position on the work.","task":"Write the 3-sentence response: genuine acknowledgment, the position held with its reasons, and the concrete goodwill move.","tips":["Apologize for the experience without conceding the work was wrong.","State the constraint honestly: pours are continuous once started, permits set the hours.","Give something real: advance notice of the remaining pours, a named contact, the end date."],"focus":["audience","clarity"],"placeholder":"You're right that 7 a.m. on a Saturday is a hard way to wake up, and I'm sorry for that morning. Concrete pours can't stop once started and our permit sets those hours, so I won't promise what I can't keep — but I can promise 72 hours' written notice before each of the four remaining pours, my direct cell for anything on those days, and an end to major pours by October."},
    {"id":"together-constr-senior-13","level":"senior","profession":"construction","title":"The executive summary that wins the shortlist","scenario":"Your RFP response for the community centre runs sixty pages, but the evaluation committee's first cut happens on the one-page executive summary — really on its first paragraph. That paragraph must carry your whole case: the point, the proof, the differentiator, no filler.","task":"Write the 3-4 sentence opening paragraph of the executive summary.","tips":["Sentence one is your entire case compressed — write it last, place it first.","Two proof points with numbers; adjectives are not evidence.","Name the differentiator honestly: the thing the other bidders cannot copy by Thursday."],"focus":["impact","concision"],"placeholder":"We will deliver this community centre for a fixed $23.4M, open for September 2028 registration — and our last six public buildings finished on the promised date at an average of 1.6% over original contract, a record we invite you to verify with those owners. What we bring that others cannot: the team that built the Riverside aquatic centre, intact, including the pool-systems subs whose work your operators still maintain."},
    {"id":"together-constr-senior-14","level":"senior","profession":"construction","title":"The handover before the holiday","scenario":"You're away for two weeks and your senior coordinator runs three live jobs in your absence. One message has to arm her: the single thing that matters on each job, the decisions she owns versus the ones that wait, and who to call when it goes sideways. Structure is the kindness here.","task":"Write the 4-sentence handover: one sentence per job with its live risk, then the decision boundary.","tips":["One job per sentence: the milestone, the risk, the trigger to act.","Draw the authority line explicitly: what she decides, what waits, what interrupts your holiday.","Name the backstops: the engineer, the lawyer, the one client to handle with care."],"focus":["structure","precision"],"placeholder":"Three jobs, one sentence each. Harbourfront: the crane comes down Thursday — if winds delay it, take the Saturday slot and eat the premium, decided. Meadowvale: pay app 4 must reach the bank by the 15th; the package is done, just certify and send. Or Street: nothing moves until the engineer's shoring letter lands — if the sub pressures you to dig, the answer is no. You own everything under $10K and anything on safety; new COs above that wait for me — and call me, any hour, for anything involving the words 'stop-work' or 'lawyer.'"},
    {"id":"together-constr-senior-15","level":"senior","profession":"construction","title":"Opening the renegotiation","scenario":"Steel prices collapsed 12% since your fabricator locked his price — and last year, when they spiked, he came to you and you gave him 6%. Now you're making the reverse call. The opener must state the ask plainly, invoke the precedent without weaponizing it, and keep a partner you need for a decade.","task":"Write the 2-3 sentence opener for the call: the ask, the precedent, the partnership frame.","tips":["Make the ask in numbers, first sentence.","The precedent is your leverage — state it once, warmly, and let it work.","Frame the goal as the relationship's rule: fairness that runs both directions."],"focus":["impact","structure"],"placeholder":"Steel is off 12% from when we locked your price, and I'm calling to share that move the same way we shared the last one — you'll remember I gave you 6% when the market went against you in March. I'm asking for 8 points back on the unfabricated tonnage, and I want the same rule to keep working both ways for the next ten years of jobs."},
    {"id":"together-constr-senior-16","level":"senior","profession":"construction","title":"The year-end letter worth reading","scenario":"Your annual letter to clients and referral sources usually says 'thanks for a great year' and evaporates. This year deserves better: two projects finished, an award, a new preconstruction service — woven into four sentences that position the firm without a single brag adjective.","task":"Write the 3-4 sentence letter: warm open, the facts allowed to brag for themselves, the one forward note.","tips":["Facts carry the positioning: names, dates, one number — no 'incredibly proud.'","One sentence of genuine thanks aimed at what clients actually did.","Close forward: the new capability, offered not announced."],"focus":["audience","concision"]},
    {"id":"together-constr-senior-17","level":"senior","profession":"construction","title":"The settlement offer, worded precisely","scenario":"The flooring defect dispute has burned four months and the lawyers are next. You're offering $45,000 to end it — an offer that must be generous enough to close, precise enough to be final, and worded so it can never be read as admitting the defect was yours.","task":"Write the 2-3 sentence offer: the number and its conditions, the without-prejudice framing, the deadline.","tips":["'Without admission of liability, and to resolve the matter fully' — the frame does the legal work.","Final means final: full and final settlement, release signed, deadline attached.","A clean expiry date creates the decision you've been waiting four months for."],"focus":["precision","impact"],"placeholder":"Without any admission of liability, and to bring this to a close for both of us, we offer $45,000 in full and final settlement of all claims relating to the flooring, conditional on a signed mutual release. The offer stands until the 30th; after that we both spend the difference on lawyers instead."},
    {"id":"together-constr-senior-18","level":"senior","profession":"construction","title":"Opening the workout presentation","scenario":"The project is $1.1M over and four months late, and the lender has assembled its special-loans team. You present for twenty minutes; the first ninety seconds decide whether they hear a failing borrower or a builder in command of a recoverable situation. Every skill shows up here, or none do.","task":"Speak the opening 3 sentences: the situation owned in numbers, the plan's shape announced, the ask named.","tips":["Say the bad numbers yourself, first and precisely — commanding the facts is the presence.","Announce the structure: the causes in two minutes, the plan in ten, the ask at the end.","Name the ask up front anyway: they'll listen better knowing where you're going."],"focus":["impact","structure"],"placeholder":"The project is $1.1M over budget and four months late — I'll own those numbers and then show you why the building still finishes and the loan still performs. Twenty minutes: two on how we got here, ten on the recovery plan and its evidence, and at the end I'm asking for a 90-day extension and no other changes to the facility."},
    {"id":"together-constr-senior-19","level":"senior","profession":"construction","title":"Forty slides become one page","scenario":"The developer's investment committee gave you fifteen minutes that just became five — the deck is dead. Everything now rides on one page: the go/no-go on the $31M phase two, your recommendation, the three numbers that drive it, and the risk stated honestly enough to be believed.","task":"Write the one-page memo's 4-sentence core: recommendation, the three numbers, the honest risk, the ask.","tips":["Recommendation first — the committee reads sentence one and skims the rest.","Three numbers maximum; the fourth dilutes the third.","State the killer risk yourself, with its mitigation — credibility is the currency here."],"focus":["concision","structure"],"placeholder":"I recommend proceeding with phase two at the guaranteed $31.2M. Three numbers drive it: construction pricing is 9% below our pro forma, phase one closed at 2% over contract, and the same team and trades carry straight over with zero remobilization. The honest risk is the electrical-switchgear market — 52-week leads — which is why this price is conditional on releasing that order within 30 days of your approval."},
    {"id":"together-constr-senior-20","level":"senior","profession":"construction","title":"Forty words on the hoarding","scenario":"The city requires a public notice board on your site hoarding, and you get roughly forty words that thousands of neighbours will skim at a bus stop. Project, dates, hours, and the number a human answers — audience-first writing at its most compressed.","task":"Write the notice: 40 words maximum, everything a resident needs, nothing else.","tips":["Lead with what it becomes, not who's building it.","The three facts residents want: how long, what hours, who answers the phone.","Cut every word that serves the company instead of the reader."],"focus":["concision","audience"],"placeholder":"Building 48 new homes here — construction until fall 2027. Work hours: 7 a.m.–6 p.m. weekdays, 9–5 Saturdays. Questions or concerns, day or night: 416-555-0180. A person answers. — Reyes Construction for Dundas West Homes"},
    {"id":"together-constr-senior-21","level":"senior","profession":"construction","title":"The reference call you owe","scenario":"A developer is checking references on your former project manager — good PM, real strengths, one genuine weakness in cost reporting that they'd be negligent not to manage. The call needs structure, honesty, and precision: praise that's specific enough to believe, and the flag delivered fairly.","task":"Speak the 3-sentence reference: the endorsement with evidence, the honest flag with its size, the net recommendation.","tips":["Specific beats glowing: name the project and what he actually did.","One real flag, sized fairly — a flagless reference is discounted to zero.","End with the clear net: would you hire him again, yes or no."],"focus":["structure","audience"]},
    {"id":"together-constr-senior-22","level":"senior","profession":"construction","title":"The eleven-month letter","scenario":"Your standard warranty expires at twelve months, and the smartest letter you send all year goes out at month eleven: inviting the homeowners to a walkthrough before the deadline. It must state the deadline plainly, offer the inspection generously, and read as service rather than clock-running.","task":"Write the 3-sentence letter: the offer, the deadline stated in their interest, the logistics made easy.","tips":["Lead with the offer, not the expiry — the frame is service.","State the date plainly anyway; hiding it would be the clock-running move.","Make yes effortless: two proposed dates, one reply needed."],"focus":["audience","clarity"],"placeholder":"Your home turns one in November, and before the twelve-month warranty closes on the 15th we'd like to walk it with you and fix anything it owes you — seasonal settling, doors, caulking, all of it. We're holding the mornings of October 28 and November 4; reply with either and we'll bring the list from your last note plus our own inspection."},
    {"id":"together-constr-senior-23","level":"senior","profession":"construction","title":"The last message before adjudication","scenario":"The $190,000 dispute with the mechanical sub goes to adjudication Friday unless this message lands. It's the full test: the gap stated precisely, your final position owned, the settlement door held open without weakness, and a register the adjudicator could later read without it costing you.","task":"Write the 3-sentence message: where the numbers stand, your final offer, and the honest fork ahead.","tips":["State both positions and the gap in one neutral sentence.","'Final' must be true — a final offer that moves teaches them to wait you out.","Write it knowing the adjudicator may read it: factual, fair, zero heat."],"focus":["precision","impact"],"placeholder":"We stand at $95,000 against your $190,000, and Friday the gap goes to an adjudicator who will cost us both more than it. My final offer is $120,000, paid within ten days of a signed release — it reflects the rework records on both sides, and I'm comfortable letting an adjudicator see that math if it comes to that. The offer expires Thursday at noon."},
    {"id":"together-constr-senior-24","level":"senior","profession":"construction","title":"Announcing the succession","scenario":"After thirty years, you're handing field operations to your longtime VP while you move to client and preconstruction work. Clients who hired the company because of you need to hear it from you — framed as strength, specific about what changes and what doesn't, and honest about why she's ready.","task":"Write the 3-4 sentence announcement: the change stated plainly, her credentials in evidence, what stays the same for them.","tips":["Say the change in sentence one; a slow reveal reads as bad news.","Her record is the reassurance: the projects she's already run for them, by name.","Be precise about your own role — 'still here' must mean something checkable."],"focus":["audience","impact"],"placeholder":"After thirty years running our field operations, I'm handing that role to Maria Santos on January 1 — and I want you to hear from me why that's good news for your projects. Maria has run our three largest jobs of the past five years, including your distribution centre, which finished eleven days early. I'm not leaving: I'll lead preconstruction and remain your first call on every new project we price together."},
    {"id":"together-constr-senior-25","level":"senior","profession":"construction","title":"The rewrite that proves the course","scenario":"Here is a real update, as first drafted: 'Just wanted to touch base regarding the project. Things have been progressing although we've had some challenges with weather and a few other items. The schedule may be somewhat impacted but we're monitoring it. We should probably discuss the budget too at some point.' Every sin at once: no point, no structure, no numbers, no ownership.","task":"Rewrite it in 4 sentences: the point first, real numbers, the ask, a position owned.","tips":["Find the buried news — a slip and an overrun — and put both in sentence one.","Replace every vague word with a number or a date.","End with the specific ask 'we should probably discuss' was hiding."],"focus":["concision","impact"],"placeholder":"Two pieces of news: the schedule has slipped eight working days from the March rains, and the budget is trending $60,000 over on sitework. The slip is recoverable — resequencing interior trades claws back five days at no cost, and I've already issued the revised look-ahead. The $60,000 is not recoverable, and I recommend funding it from contingency, which stands at $180,000. I need thirty minutes Thursday to walk you through both and get your sign-off."}
  ],
};
